if(!window.MM) window.MM={};
window.MM['oph_p2_glaucoma']=[
  {q:"A 58-year-old man undergoing routine examination has intraocular pressure of 28 mmHg, enlarged cup-disc ratio, and corresponding nasal visual field defects. Gonioscopy reveals open anterior chamber angles. Which diagnosis is most likely?",o:["Primary angle-closure glaucoma","Secondary neovascular glaucoma","Primary open-angle glaucoma","Acute iridocyclitis","Normal tension glaucoma"],a:2,e:"Primary open-angle glaucoma (POAG) is characterized by progressive optic neuropathy with corresponding visual field defects despite anatomically open anterior chamber angles. Elevated intraocular pressure is a major risk factor.<br><br>POAG is often asymptomatic until advanced disease develops. Identifying ocular hypertension that warrants monitoring versus treatment is a recurring clinical-judgement scenario.<br><br>Angle-closure glaucoma (A) presents with narrow or closed angles and often acute symptoms. Normal tension glaucoma (E) demonstrates glaucomatous damage despite statistically normal intraocular pressure.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which risk factor is most strongly associated with primary open-angle glaucoma?",o:["High myopia","Hyperopia","Shallow anterior chamber","Young age","Blue iris color"],a:0,e:"High myopia is a recognized risk factor for primary open-angle glaucoma because myopic optic discs may be structurally more susceptible to glaucomatous damage.<br><br>Other major risk factors include age, family history, African ancestry, and elevated IOP.<br><br>Hyperopia (B) and shallow anterior chamber (C) are more strongly associated with angle-closure glaucoma. Young age (D) is less strongly associated with POAG development.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which visual field defect is classically seen early in primary open-angle glaucoma?",o:["Central scotoma","Bitemporal hemianopia","Homonymous hemianopia","Arcuate scotoma","Altitudinal defect"],a:3,e:"Arcuate scotomas occur because glaucomatous damage preferentially affects retinal nerve fiber bundles following arcuate patterns around fixation.<br><br>Bjerrum scotoma and nasal step are among the earliest and highest-yield glaucomatous visual field defects.<br><br>Bitemporal hemianopia (B) suggests chiasmal pathology. Homonymous hemianopia (C) indicates retrochiasmal neurological lesions. Central scotoma (A) is more typical of optic neuritis.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which optic disc change is most characteristic of chronic open-angle glaucoma?",o:["Disc swelling","Temporal pallor only","Increased cup-disc ratio","Cherry-red spot","Optic disc drusen"],a:2,e:"Progressive optic nerve head cupping is the hallmark structural feature of glaucomatous optic neuropathy. Loss of neuroretinal rim tissue enlarges the optic cup progressively.<br><br>Vertical enlargement of cupping is particularly characteristic and.<br><br>Disc swelling (A) suggests papilledema or optic neuritis. Cherry-red spot (D) occurs in CRAO. Optic disc drusen (E) represent calcified deposits unrelated to glaucomatous cupping.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which structure primarily offers resistance to aqueous outflow in primary open-angle glaucoma?",o:["Lens capsule","Iris root","Ciliary body","Trabecular meshwork","Corneal epithelium"],a:3,e:"In primary open-angle glaucoma, impaired aqueous drainage through the trabecular meshwork increases intraocular pressure despite anatomically open angles.<br><br>Microscopic trabecular dysfunction rather than visible angle closure explains the disease mechanism.<br><br>The iris root (B) contributes more directly to angle-closure mechanisms. Ciliary body (C) produces aqueous humor but is not the primary outflow resistance site in POAG.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which investigation is essential for confirming open anterior chamber angles in suspected POAG?",o:["Gonioscopy","Retinoscopy","Schirmer testing","Keratometry","Hess charting"],a:0,e:"Gonioscopy directly visualizes the anterior chamber angle and is essential to confirm that the angle remains open in POAG.<br><br>Differentiation between open-angle and angle-closure glaucoma is fundamental in glaucoma diagnosis and.<br><br>Retinoscopy (B) assesses refractive status. Schirmer testing (C) evaluates tear production. Keratometry (D) measures corneal curvature.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which symptom is most characteristic of chronic primary open-angle glaucoma in early stages?",o:["Severe ocular pain","Colored halos","Usually asymptomatic","Sudden profound blindness","Acute redness"],a:2,e:"Primary open-angle glaucoma progresses slowly and painlessly, often remaining asymptomatic until substantial visual field loss has occurred.<br><br>Severe pain (A), halos (B), and acute redness (E) are more typical of acute angle-closure glaucoma rather than chronic POAG.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which visual field defect is classically associated with early glaucoma?",o:["Nasal step","Ring scotoma","Central hemianopia","Total blindness initially","Binasal hemianopia"],a:0,e:"Nasal step defects arise because glaucomatous damage respects the horizontal raphe of retinal nerve fibers.<br><br>Bjerrum arcuate scotoma often accompanies it.<br><br>Ring scotoma (B) is more characteristic of retinitis pigmentosa. Binasal hemianopia (E) is rare and not a classic glaucoma field defect.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which medication class decreases aqueous humor production in POAG?",o:["Prostaglandin analogues","Beta blockers","Miotics only","Hyperosmotics only","Cycloplegics"],a:1,e:"Topical beta blockers such as timolol reduce aqueous humor production by the ciliary epithelium and therefore lower intraocular pressure.<br><br>They remain important glaucoma medications despite increasing use of prostaglandin analogues. This pharmacologic mechanism is.<br><br>Prostaglandin analogues (A) primarily increase uveoscleral outflow rather than markedly reducing aqueous production. Cycloplegics (E) are not standard POAG therapy.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which glaucoma medication is considered first-line because of strong IOP-lowering effect and once-daily dosing?",o:["Pilocarpine","Atropine","Topical antibiotic","Prostaglandin analogue","Cyclopentolate"],a:3,e:"Prostaglandin analogues such as latanoprost effectively reduce intraocular pressure by increasing uveoscleral outflow and require convenient once-daily dosing.<br><br>Pilocarpine (A) is less commonly used because of side effects and frequent dosing. Atropine (B) may precipitate angle closure in susceptible individuals.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which optic disc feature is strongly suggestive of glaucomatous damage?",o:["Neuroretinal rim thinning","Blurred disc margins","Macular star","Disc hemorrhage absent always","Papilledema"],a:0,e:"Progressive thinning of the neuroretinal rim, especially inferotemporally and superotemporally, strongly suggests glaucomatous optic neuropathy.<br><br>Blurred margins (B) suggest optic disc edema rather than glaucoma. Papilledema (E) reflects raised intracranial pressure rather than chronic glaucomatous cupping.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which tonometry method is considered gold standard for intraocular pressure measurement?",o:["Goldmann applanation tonometry","Schiotz tonometry","Digital palpation","Rebound tonometry only","Pneumotonometry only"],a:0,e:"Goldmann applanation tonometry remains the gold standard method for intraocular pressure measurement because of excellent accuracy and reproducibility.<br><br>Digital palpation (C) is crude and unreliable. Schiotz tonometry (B) is indentation tonometry and less accurate than applanation methods.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which glaucoma surgery creates an alternate pathway for aqueous drainage?",o:["Trabeculectomy","DCR","Keratoplasty","Vitrectomy","Cycloplegia"],a:0,e:"Trabeculectomy creates a guarded fistula that allows aqueous humor to bypass trabecular resistance and drain into a subconjunctival bleb.<br><br>DCR (B) is lacrimal surgery. Keratoplasty (C) treats corneal disease. Vitrectomy (D) addresses vitreoretinal pathology rather than aqueous outflow.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which factor is the strongest modifiable risk factor for progression of POAG?",o:["Iris color","Elevated intraocular pressure","Gender only","Refractive error alone","Corneal diameter"],a:1,e:"Elevated intraocular pressure is the most important modifiable risk factor in glaucoma progression, and lowering IOP significantly slows disease progression.<br><br>Iris color (A) and corneal diameter (E) are not major modifiable progression factors. Refractive error alone (D) is not the primary therapeutic target.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which visual function is generally preserved until late in open-angle glaucoma?",o:["Peripheral vision","Color vision always","Central visual acuity","Dark adaptation only","Contrast sensitivity only"],a:2,e:"Peripheral visual field loss occurs early in glaucoma, while central visual acuity often remains preserved until advanced disease stages.<br><br>This explains why many glaucoma patients remain asymptomatic despite substantial peripheral field damage.<br><br>Peripheral vision (A) is typically affected earlier. Contrast sensitivity (E) and color discrimination may become abnormal before central acuity declines severely.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which sign is classically associated with glaucomatous optic disc damage?",o:["Bayonetting of vessels","Disc hyperemia only","Cherry-red spot","Macular edema","Roth spots"],a:0,e:"Bayonetting occurs when retinal vessels abruptly change direction over a deeply excavated glaucomatous optic cup.<br><br>Cherry-red spot (C) is characteristic of CRAO. Roth spots (E) occur in infective endocarditis or hematologic disorders.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which type of glaucoma may occur despite statistically normal intraocular pressure?",o:["Congenital glaucoma","Neovascular glaucoma","Phacomorphic glaucoma","Normal tension glaucoma","Lens-induced glaucoma"],a:3,e:"Normal tension glaucoma demonstrates characteristic glaucomatous optic neuropathy and visual field loss despite IOP within statistically normal range.<br><br>Vascular dysregulation and optic nerve susceptibility are believed to contribute significantly.<br><br>Neovascular glaucoma (B) typically causes markedly elevated IOP. Congenital glaucoma (A) presents in infancy with buphthalmos and tearing.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which glaucoma medication primarily increases uveoscleral outflow?",o:["Beta blockers","Carbonic anhydrase inhibitors","Alpha agonists only","Prostaglandin analogues","Hyperosmotics"],a:3,e:"Prostaglandin analogues lower intraocular pressure primarily by increasing uveoscleral aqueous outflow.<br><br>They are highly effective and widely used first-line glaucoma medications.<br><br>Beta blockers (A) mainly decrease aqueous production. Hyperosmotics (E) are generally used for acute severe IOP elevation rather than chronic POAG management.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which glaucoma investigation evaluates retinal nerve fiber layer thickness?",o:["OCT","Gonioscopy","Schirmer testing","Retinoscopy","Keratometry"],a:0,e:"Optical coherence tomography quantitatively measures retinal nerve fiber layer thickness and helps detect early glaucomatous structural damage.<br><br>Gonioscopy (B) assesses anterior chamber angle anatomy rather than nerve fiber thickness. Retinoscopy (D) measures refractive status.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which statement regarding primary open-angle glaucoma is most accurate?",o:["It always presents acutely","It commonly causes painful red eye early","It is a chronic progressive optic neuropathy","It always causes blindness rapidly","It occurs only with closed angles"],a:2,e:"Primary open-angle glaucoma is a chronic progressive optic neuropathy characterized by optic disc cupping and corresponding visual field loss, usually associated with elevated intraocular pressure.<br><br>The disease progresses slowly and silently, making screening and long-term follow-up critically important.<br><br>Painful acute presentations (A, B) are more characteristic of angle-closure glaucoma. POAG occurs despite anatomically open angles, making option E incorrect.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 67-year-old diabetic patient with progressive peripheral visual field loss has IOP of 30 mmHg and bilateral optic disc cupping. Which visual field defect is most characteristic of moderate POAG?",o:["Central scotoma","Arcuate Bjerrum scotoma","Bitemporal hemianopia","Homonymous hemianopia","Ring scotoma"],a:1,e:"Bjerrum arcuate scotoma develops due to damage of arcuate retinal nerve fiber bundles and is highly characteristic of glaucomatous optic neuropathy.<br><br>Nasal step defects may coexist.<br><br>Bitemporal hemianopia (C) indicates chiasmal lesions. Homonymous hemianopia (D) suggests retrochiasmal neurological pathology. Ring scotoma (E) is more characteristic of retinitis pigmentosa.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which factor most significantly increases the risk of POAG progression despite treatment?",o:["Thin central corneal thickness","Blue iris color","Mild hyperopia","Young age alone","Corneal astigmatism"],a:0,e:"Thin central corneal thickness is an important independent risk factor for glaucoma progression and may also cause underestimation of intraocular pressure measurements.<br><br>Hyperopia (C) is more associated with angle-closure glaucoma. Corneal astigmatism (E) is not a major independent progression risk factor.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which retinal nerve fiber layer change is earliest in glaucoma?",o:["Generalized edema","Localized thinning","Retinal hemorrhage only","Macular edema","Retinal detachment"],a:1,e:"Localized retinal nerve fiber layer thinning may precede obvious visual field defects and represents early structural glaucomatous damage.<br><br>Modern OCT imaging detects these early changes and has become increasingly important in glaucoma diagnosis.<br><br>Generalized edema (A) suggests inflammatory or vascular pathology rather than glaucoma. Retinal detachment (E) is unrelated to optic neuropathy progression.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which medication is contraindicated in patients with asthma and POAG?",o:["Timolol","Latanoprost","Brimonidine","Dorzolamide","Acetazolamide"],a:0,e:"Timolol is a nonselective beta blocker and may precipitate bronchospasm in asthmatic patients because of beta-2 receptor blockade.<br><br>Careful systemic history is essential before prescribing topical beta blockers.<br><br>Latanoprost (B) primarily increases uveoscleral outflow and is generally safer in asthma. Dorzolamide (D) is a carbonic anhydrase inhibitor rather than beta blocker.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which optic disc hemorrhage is classically associated with glaucoma progression?",o:["Flame hemorrhage at disc margin","Subhyaloid hemorrhage","Vitreous hemorrhage","Roth spot hemorrhage","Preretinal hemorrhage"],a:0,e:"Splinter or flame-shaped hemorrhages at the optic disc margin are strongly associated with active glaucomatous progression and optic nerve damage.<br><br>Subhyaloid hemorrhage (B) and preretinal hemorrhage (E) are usually associated with retinal vascular disorders rather than glaucomatous optic neuropathy.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which mechanism best explains optic nerve damage in POAG?",o:["Mechanical and vascular optic nerve injury","Corneal edema only","Retinal detachment alone","Lens-induced ischemia","Choroidal rupture"],a:0,e:"Glaucomatous optic neuropathy results from combined mechanical compression and vascular insufficiency affecting retinal ganglion cell axons at the lamina cribrosa.<br><br>Elevated IOP remains the major modifiable factor.<br><br>Corneal edema (B) occurs secondarily in severe glaucoma but does not explain optic nerve damage directly. Retinal detachment (C) is unrelated to POAG pathogenesis.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which symptom may occasionally occur in chronic POAG despite its generally silent nature?",o:["Mild frontal headache","Severe nausea and vomiting","Sudden painful blindness","Colored halos in every patient","Profound photophobia"],a:0,e:"Although POAG is usually asymptomatic, some patients may report mild ocular discomfort or frontal headache due to chronically elevated intraocular pressure.<br><br>However, severe painful symptoms are much more characteristic of angle-closure glaucoma.<br><br>Nausea and vomiting (B) and sudden painful blindness (C) suggest acute angle closure rather than chronic open-angle disease.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which gonioscopic finding is expected in primary open-angle glaucoma?",o:["Closed angle with peripheral anterior synechiae","Narrow slit-like angle only","Iris bombe","Open anterior chamber angle","Neovascular membrane across angle"],a:3,e:"POAG demonstrates anatomically open anterior chamber angles despite impaired aqueous drainage through the trabecular meshwork.<br><br>Gonioscopy is therefore essential in differentiating POAG from angle-closure glaucoma.<br><br>Peripheral anterior synechiae (A) and iris bombe (C) are characteristic of angle-closure mechanisms rather than POAG.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which class of glaucoma medication may cause eyelash growth and iris pigmentation?",o:["Beta blockers","Miotics","Prostaglandin analogues","Hyperosmotics","Cycloplegics"],a:2,e:"Prostaglandin analogues may cause increased eyelash growth, periocular pigmentation, and gradual darkening of iris color, especially in mixed-color irides.<br><br>Beta blockers (A) mainly produce cardiovascular and respiratory adverse effects rather than iris pigmentation changes. Miotics (B) commonly cause brow ache and miosis.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which finding most strongly suggests advanced glaucomatous optic atrophy?",o:["Cup-disc ratio of 0.2","Total optic disc pallor only","Papilledema","Bean-pot cupping","Optic neuritis"],a:3,e:"Bean-pot cupping refers to deep excavation with overhanging disc margins seen in advanced glaucomatous optic nerve damage.<br><br>Papilledema (C) involves swollen discs due to raised intracranial pressure. Optic neuritis (E) usually causes painful visual loss with less prominent cupping.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which glaucoma medication decreases aqueous production by inhibiting carbonic anhydrase?",o:["Latanoprost","Timolol","Dorzolamide","Pilocarpine","Atropine"],a:2,e:"Dorzolamide is a topical carbonic anhydrase inhibitor that lowers intraocular pressure by reducing aqueous humor production in the ciliary body.<br><br>This pharmacologic mechanism is a. Systemic acetazolamide acts similarly.<br><br>Pilocarpine (D) increases trabecular outflow through ciliary muscle contraction rather than inhibiting aqueous formation. Atropine (E) may worsen angle closure.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which optic nerve rule is commonly used in glaucoma disc assessment?",o:["Rule of thirds","ISNT rule","Rule of nines","Snell rule","Ferris rule"],a:1,e:"The ISNT rule states that normal neuroretinal rim thickness decreases in the order Inferior \\> Superior \\> Nasal \\> Temporal. Violation suggests glaucoma.<br><br>The rule of thirds (A) relates more to retinal vessel evaluation. Snell rule (D) is unrelated to glaucoma optic nerve analysis.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which patient has the greatest risk for developing POAG?",o:["Elderly patient with positive family history","Young hyperopic female","Child with congenital cataract","Patient with corneal abrasion","Acute conjunctivitis patient"],a:0,e:"Increasing age and positive family history are among the strongest risk factors for POAG development.<br><br>First-degree relatives of glaucoma patients possess significantly increased disease risk, making family screening important.<br><br>Hyperopia (B) is more associated with angle closure rather than POAG. Conjunctivitis (E) and corneal abrasion (D) are unrelated surface disorders.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which structure is damaged first in glaucoma?",o:["Retinal ganglion cell axons","Corneal epithelium","Lens fibers","Retinal pigment epithelium","Iris stroma"],a:0,e:"Glaucoma primarily damages retinal ganglion cell axons at the optic nerve head, causing progressive optic neuropathy and visual field defects.<br><br>Axonal loss precedes clinically detectable visual field impairment, making structural imaging increasingly valuable in early diagnosis.<br><br>Corneal epithelium (B) and lens fibers (C) are not primary targets in POAG pathogenesis.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which visual field region is usually affected first in POAG?",o:["Peripheral field","Central fixation","Temporal hemifield only","Entire field equally","Inferior hemianopia only"],a:0,e:"Peripheral visual field loss occurs early in glaucoma because arcuate retinal nerve fiber bundles are preferentially damaged initially.<br><br>Central vision is generally preserved until advanced disease stages, contributing to delayed diagnosis.<br><br>Central fixation (B) is usually spared initially. Entire field involvement (D) occurs only in end-stage disease.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which glaucoma medication commonly causes brow ache and induced myopia?",o:["Timolol","Pilocarpine","Latanoprost","Brimonidine","Dorzolamide"],a:1,e:"Pilocarpine is a miotic that contracts the ciliary muscle, often producing brow ache, accommodative spasm, and transient induced myopia.<br><br>Latanoprost (C) more commonly causes eyelash growth and iris pigmentation. Timolol (A) may cause bronchospasm or bradycardia.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which investigation is most useful for monitoring glaucoma progression over time?",o:["Serial visual field analysis","Color vision testing only","Schirmer testing","Exophthalmometry","Corneal scraping"],a:0,e:"Serial automated perimetry is crucial for monitoring functional progression of glaucomatous visual field loss over time.<br><br>Color vision testing (B) may be abnormal but is less useful for serial progression monitoring. Schirmer testing (C) evaluates tear production only.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which factor may falsely elevate measured intraocular pressure?",o:["Thick cornea","Thin cornea","Retinal thinning","Myopia only","Cataract formation"],a:0,e:"Thick central corneal thickness may falsely elevate measured intraocular pressure during applanation tonometry.<br><br>Understanding corneal thickness influence on IOP interpretation is highly important and.<br><br>Thin cornea (B) generally causes underestimation of true intraocular pressure. Cataract formation (E) does not directly alter applanation measurements significantly.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which condition is most strongly associated with normal tension glaucoma?",o:["Vascular dysregulation","Corneal ulceration","Acute uveitis","Retinal detachment","Hyperopia"],a:0,e:"Vascular dysregulation and impaired optic nerve perfusion are strongly implicated in normal tension glaucoma pathogenesis.<br><br>Migraine, Raynaud phenomenon, and systemic hypotension are commonly associated.<br><br>Corneal ulceration (B) and acute uveitis (C) are unrelated inflammatory disorders rather than vascular optic neuropathic mechanisms.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which statement regarding POAG management is most accurate?",o:["Treatment is unnecessary until symptoms occur","Lowering IOP slows disease progression","Surgery is always first-line therapy","Visual field loss is fully reversible","Gonioscopy is unnecessary"],a:1,e:"Reduction of intraocular pressure remains the only proven strategy to slow progression of glaucomatous optic neuropathy.<br><br>Management may involve medications, laser therapy, or surgery depending on disease severity and progression.<br><br>Visual field loss (D) is generally irreversible because retinal ganglion cell axons do not regenerate significantly. Gonioscopy (E) remains essential for glaucoma classification.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"A 63-year-old woman with POAG on topical therapy develops progressive visual field loss despite apparently controlled IOP. Which factor should be reassessed because it may falsely underestimate IOP?",o:["Thin cornea","Thick cornea","Cataract density","Vitreous liquefaction","Iris color"],a:0,e:"Thin central corneal thickness may lead to falsely low applanation tonometry readings, masking inadequately controlled glaucoma.<br><br>Thick cornea (B) falsely elevates measured IOP rather than lowering it. Cataract density (C) does not significantly cause systematic underestimation during Goldmann applanation tonometry.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which optic disc feature is considered most characteristic of glaucomatous damage rather than nonglaucomatous optic atrophy?",o:["Cupping greater than pallor","Diffuse pallor greater than cupping","Disc edema","Hyperemic disc swelling","Optic disc drusen"],a:0,e:"In glaucoma, optic disc cupping is disproportionately greater than pallor because retinal ganglion cell axons are progressively lost.<br><br>Diffuse pallor exceeding cupping (B) suggests nonglaucomatous optic neuropathy such as compressive or ischemic disease. Disc edema (C) indicates acute swelling rather than chronic glaucoma.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A patient using latanoprost for POAG notices gradual darkening of iris color and longer eyelashes. Which mechanism best explains these changes?",o:["Corneal epithelial toxicity","Sympathetic stimulation","Acute allergic inflammation","Increased melanogenesis and follicular stimulation","Lens epithelial proliferation"],a:3,e:"Prostaglandin analogues increase melanogenesis within iris melanocytes and stimulate eyelash follicles, causing iris darkening and eyelash growth.<br><br>Corneal epithelial toxicity (A) does not explain iris pigmentation changes. Acute allergic inflammation (C) would cause redness and irritation rather than gradual pigmentation.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which visual field defect is considered highly characteristic of glaucoma because it respects the horizontal meridian?",o:["Central scotoma","Altitudinal defect","Nasal step","Bitemporal hemianopia","Junctional scotoma"],a:2,e:"The nasal step occurs because glaucomatous retinal nerve fiber damage respects the horizontal raphe. It is a classic early glaucomatous field defect.<br><br>Bitemporal hemianopia (D) suggests optic chiasm pathology. Central scotoma (A) is more typical of optic neuritis or toxic optic neuropathy.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which systemic disease is strongly associated with development and progression of normal tension glaucoma?",o:["Migraine and vasospastic disorders","Bronchial asthma only","Chronic otitis media","Rheumatic fever","Peptic ulcer disease"],a:0,e:"Vascular dysregulation plays a major role in normal tension glaucoma, and patients commonly have migraine, Raynaud phenomenon, or systemic hypotension.<br><br>Bronchial asthma (B) is clinically relevant mainly because beta blockers may be contraindicated in glaucoma therapy. Chronic otitis media (C) has no direct glaucoma association. The strong diabetic association with neovascular glaucoma progression is a recurring systemic link.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which examination finding is most suggestive of progressive glaucomatous optic neuropathy?",o:["Increasing vertical cup-disc ratio","Stable neuroretinal rim","Disc edema","Cherry-red spot","Macular star"],a:0,e:"Progressive enlargement of vertical cup-disc ratio indicates ongoing glaucomatous loss of neuroretinal rim tissue.<br><br>Disc edema (C) is associated with papilledema or optic neuritis rather than glaucoma. Cherry-red spot (D) indicates CRAO.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A glaucoma patient develops bradycardia and bronchospasm after topical therapy. Which medication is the most likely cause?",o:["Pilocarpine","Timolol","Latanoprost","Brinzolamide","Acetazolamide"],a:1,e:"Timolol is a nonselective beta blocker that may cause systemic beta blockade after topical absorption, leading to bradycardia and bronchospasm.<br><br>Pilocarpine (A) more commonly causes brow ache and accommodative spasm. Latanoprost (C) typically causes eyelash growth and iris pigmentation.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which OCT finding most strongly supports early glaucomatous damage?",o:["Increased macular thickness","Retinal detachment","Vitreous hemorrhage","Retinal nerve fiber layer thinning","Choroidal thickening"],a:3,e:"OCT-detected retinal nerve fiber layer thinning may identify structural glaucomatous damage before obvious visual field defects become apparent.<br><br>Retinal detachment (B) and vitreous hemorrhage (C) represent vitreoretinal disorders rather than glaucomatous optic neuropathy.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which statement regarding visual loss in POAG is most accurate?",o:["Central vision is affected first","Visual loss is usually painful","Peripheral visual loss occurs gradually","Visual loss is fully reversible","Sudden blindness is typical"],a:2,e:"POAG characteristically causes slow progressive peripheral visual field loss while central vision remains preserved until late disease stages.<br><br>Because progression is painless and gradual, many patients remain unaware until advanced damage occurs.<br><br>Central vision loss (A) is generally a late finding. Sudden blindness (E) is more characteristic of vascular or acute angle-closure events.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which treatment principle is most important in long-term POAG management?",o:["Lowering IOP below target pressure","Intermittent therapy only during symptoms","Avoiding all surgical options","Treating only visual acuity loss","Stopping therapy after field stabilization"],a:0,e:"Long-term glaucoma management aims to maintain intraocular pressure below an individualized target level to slow structural and functional progression.<br><br>Target pressure depends on disease severity, progression rate, baseline IOP, and life expectancy.<br><br>POAG therapy is continuous rather than symptom-based because the disease is usually asymptomatic. Visual acuity alone (D) is insufficient for monitoring disease progression.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"A 60-year-old hyperopic woman presents with sudden severe ocular pain, headache, nausea, blurred vision, and colored halos around lights. Examination reveals mid-dilated fixed pupil and corneal edema. Which diagnosis is most likely?",o:["Acute angle-closure glaucoma","Acute iridocyclitis","Central retinal artery occlusion","Open-angle glaucoma","Optic neuritis"],a:0,e:"Acute angle-closure glaucoma presents with sudden painful red eye, markedly elevated intraocular pressure, corneal edema, halos around lights, and systemic symptoms such as nausea and vomiting.<br><br>Open-angle glaucoma (D) is usually painless and chronic. Optic neuritis (E) causes painful visual loss but does not produce mid-dilated pupil or markedly elevated IOP.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which refractive status most strongly predisposes to primary angle-closure glaucoma?",o:["High myopia","Emmetropia","Hyperopia","Aphakia","Astigmatism"],a:2,e:"Hyperopic eyes tend to have shorter axial lengths and shallow anterior chambers, predisposing to angle crowding and angle closure.<br><br>Elderly hyperopic females are particularly susceptible.<br><br>High myopia (A) is more commonly associated with open-angle glaucoma because of elongated axial length and optic nerve vulnerability.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which mechanism most commonly initiates primary angle-closure glaucoma?",o:["Trabecular degeneration","Pupillary block","Retinal ischemia","Lens subluxation only","Vitreous hemorrhage"],a:1,e:"Pupillary block occurs when aqueous humor cannot pass freely from posterior chamber to anterior chamber, causing iris bombe and angle closure.<br><br>Trabecular degeneration (A) is more characteristic of open-angle glaucoma. Vitreous hemorrhage (E) does not typically initiate acute angle closure.<br><br><em>(Recall and Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which pupil finding is classically seen in acute angle-closure glaucoma?",o:["Pinpoint pupil","Mid-dilated fixed pupil","Irregular miotic pupil","Relative afferent pupillary defect only","Argyll Robertson pupil"],a:1,e:"The pupil in acute angle closure becomes mid-dilated and poorly reactive because iris ischemia affects sphincter muscle function.<br><br>Irregular miotic pupil (C) is more typical of anterior uveitis due to posterior synechiae formation.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which gonioscopic finding confirms angle closure?",o:["Visible trabecular meshwork","Wide ciliary body band","Appositional or synechial closure of angle","Pigmented open angle only","Increased aqueous flare only"],a:2,e:"Angle closure is confirmed when gonioscopy demonstrates obstruction of trabecular meshwork by peripheral iris, either appositional or synechial.<br><br>Visible trabecular meshwork (A) suggests open angles. Aqueous flare (E) indicates inflammation rather than angle anatomy. A confirmed closed angle on gonioscopy as the diagnostic anchor is an emphasised teaching point.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which medication is used immediately to rapidly lower IOP in acute angle closure?",o:["Cyclopentolate","Atropine","Acetazolamide","Tropicamide","Phenylephrine"],a:2,e:"Acetazolamide rapidly reduces aqueous humor production and is a key emergency treatment in acute angle-closure glaucoma.<br><br>It is commonly combined with topical agents and hyperosmotics in severe attacks. Rapid IOP reduction agents in the acute setting are a heavily emphasised emergency drill.<br><br>Atropine (B) and tropicamide (D) worsen angle closure by inducing mydriasis. Phenylephrine (E) may aggravate pupillary block.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which symptom strongly differentiates acute angle-closure glaucoma from chronic open-angle glaucoma?",o:["Peripheral field loss","Elevated IOP","Severe ocular pain with nausea","Optic disc cupping","Visual field defects"],a:2,e:"Acute angle closure produces sudden severe pain, headache, nausea, and vomiting because of abrupt marked IOP elevation.<br><br>Open-angle glaucoma usually progresses silently without severe acute symptoms. Halos with pain and nausea distinguishing angle closure from open-angle disease is a core teaching point.<br><br>Both diseases may produce elevated IOP (B) and optic disc cupping (D), making these less discriminatory.<br><br><em>(Recall and Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which definitive treatment is commonly performed after acute angle closure is medically controlled?",o:["Trabeculectomy immediately","Laser peripheral iridotomy","DCR","Penetrating keratoplasty","Vitrectomy"],a:1,e:"Laser peripheral iridotomy creates an alternate pathway for aqueous movement from posterior to anterior chamber, relieving pupillary block.<br><br>Trabeculectomy (A) may be required later in resistant cases but is not usually first definitive intervention after stabilization. Definitive iridotomy after the acute attack settles is a recurring management-sequence point.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which corneal finding commonly occurs in acute angle-closure glaucoma?",o:["Keratic precipitates","Corneal edema","Corneal ulceration","Band keratopathy","Keratoconus"],a:1,e:"Markedly elevated intraocular pressure impairs corneal endothelial pump function, causing corneal edema and blurred vision with halos around lights.<br><br>Keratic precipitates (A) suggest uveitis rather than angle closure. Keratoconus (E) is unrelated ectatic corneal disease.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which demographic profile classically predisposes to acute angle-closure glaucoma?",o:["Young myopic male","Elderly hyperopic female","Aphakic teenager","Child with buphthalmos","Middle-aged emmetrope only"],a:1,e:"Elderly hyperopic females are classically predisposed because aging causes lens enlargement and hyperopic eyes possess shallow anterior chambers.<br><br>Young myopic males (A) are more predisposed to retinal detachment and open-angle glaucoma rather than angle closure.<br><br><em>(Recall and Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which optic nerve change may develop after repeated untreated angle-closure attacks?",o:["Papilledema only","Optic disc cupping","Disc drusen","Cherry-red spot","Macular edema"],a:1,e:"Repeated episodes of elevated intraocular pressure eventually produce glaucomatous optic neuropathy with optic disc cupping and visual field loss.<br><br>Chronic angle closure can therefore resemble advanced POAG structurally. Glaucomatous cupping following repeated untreated attacks is an emphasised late complication.<br><br>Papilledema (A) reflects raised intracranial pressure rather than glaucoma. Cherry-red spot (D) occurs in CRAO.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which drug is contraindicated in anatomically narrow angles because it may precipitate acute angle closure?",o:["Pilocarpine","Timolol","Tropicamide","Acetazolamide","Mannitol"],a:2,e:"Mydriatic agents such as tropicamide may precipitate angle closure in susceptible individuals because pupillary dilation increases pupillary block.<br><br>Pilocarpine (A) produces miosis and may help open the angle after IOP reduction. Mannitol (E) lowers IOP rather than precipitating angle closure. Mydriatic precipitation of closure in a narrow angle is an emphasised prescribing caution.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which visual symptom is classically caused by corneal edema in acute angle closure?",o:["Diplopia","Floaters","Colored halos around lights","Metamorphopsia","Nyctalopia"],a:2,e:"Corneal epithelial edema causes diffraction of light, producing colored halos around lights in acute angle closure.<br><br>Floaters (B) usually indicate vitreoretinal pathology. Metamorphopsia (D) is associated with macular disease.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which physical examination finding is expected in acute angle-closure glaucoma?",o:["Soft eyeball on palpation","Shallow anterior chamber","Deep anterior chamber","Normal IOP","Retinal detachment"],a:1,e:"Angle-closure glaucoma typically occurs in anatomically crowded eyes with shallow anterior chambers and narrow angles.<br><br>Deep anterior chamber (C) is more typical of open-angle glaucoma. Acute angle closure produces markedly elevated IOP rather than normal pressure.<br><br><em>(Recall and Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which treatment lowers IOP by creating an osmotic gradient between plasma and vitreous?",o:["Pilocarpine","Timolol","Brimonidine","Latanoprost","Mannitol"],a:4,e:"Intravenous mannitol is a hyperosmotic agent that rapidly lowers IOP by drawing fluid from the vitreous into the intravascular compartment.<br><br>Pilocarpine (A) acts by miosis and increasing trabecular outflow rather than osmotic dehydration.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which symptom is least characteristic of acute angle-closure glaucoma?",o:["Severe headache","Nausea and vomiting","Sudden ocular pain","Painless gradual peripheral field loss","Blurred vision"],a:3,e:"Painless gradual peripheral field loss is more typical of chronic open-angle glaucoma rather than acute angle closure.<br><br>Acute angle closure is characterized by abrupt painful symptoms due to sudden severe IOP elevation.<br><br>Blurred vision (E), severe headache (A), and nausea (B) are classic acute attack features.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which mechanism explains iris bombe formation?",o:["Vitreous prolapse","Pupillary block causing posterior chamber pressure rise","Corneal endothelial failure","Lens dislocation posteriorly","Retinal ischemia"],a:1,e:"Pupillary block causes aqueous accumulation in the posterior chamber, pushing peripheral iris anteriorly and producing iris bombe.<br><br>This mechanism underlies most primary angle-closure glaucoma attacks.<br><br>Corneal endothelial failure (C) causes edema rather than iris convexity. Retinal ischemia (E) is unrelated to iris bombe formation.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which bilateral management principle is important after unilateral acute angle-closure attack?",o:["Ignore fellow eye if asymptomatic","Perform prophylactic iridotomy in fellow eye","Immediate vitrectomy in fellow eye","Use chronic mydriatics","Perform DCR prophylactically"],a:1,e:"The fellow eye often possesses similar narrow-angle anatomy and carries high risk for future acute angle closure.<br><br>Prophylactic laser peripheral iridotomy is therefore commonly recommended.<br><br>Ignoring the fellow eye (A) risks future blinding attacks. Chronic mydriatic use (D) may precipitate angle closure.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which lens-related change contributes significantly to angle closure in elderly patients?",o:["Lens flattening","Posterior lens displacement","Increased lens thickness","Lens capsule rupture","Lens coloboma"],a:2,e:"With aging, the crystalline lens enlarges and thickens, contributing to anterior chamber crowding and increased pupillary block risk.<br><br>This anatomical mechanism is. Lenticular change contributing to elderly angle closure is a recurring mechanism question.<br><br>Posterior lens displacement (B) would deepen rather than narrow the anterior chamber. Lens coloboma (E) is unrelated developmental abnormality.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which statement regarding acute angle-closure glaucoma is most accurate?",o:["It is usually asymptomatic","It primarily affects highly myopic young males","It is an ophthalmic emergency requiring urgent IOP reduction","Gonioscopy is contraindicated permanently","It never recurs after medical treatment alone"],a:2,e:"Acute angle-closure glaucoma is a true ophthalmic emergency because prolonged elevated IOP can rapidly cause irreversible optic nerve damage and permanent vision loss.<br><br>Urgent medical therapy followed by definitive laser peripheral iridotomy is the standard management strategy.<br><br>Medical therapy alone (E) does not eliminate future risk because the underlying anatomical predisposition remains.<br><br><em>(Recall and Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"A 59-year-old hypermetropic woman develops recurrent evening episodes of blurred vision with colored halos that improve after sleep. Which diagnosis is most likely?",o:["Intermittent angle-closure glaucoma","Acute iridocyclitis","Open-angle glaucoma","Optic neuritis","Retinal migraine"],a:0,e:"Intermittent angle closure produces transient pupillary block episodes, often precipitated in dim illumination when pupils become mid-dilated. Symptoms classically improve after sleep because miosis relieves the block.<br><br>Colored halos and transient evening blurring are particularly high-yield clues.<br><br>Open-angle glaucoma (C) is usually asymptomatic early. Optic neuritis (D) causes painful visual loss rather than transient haloes relieved by sleep.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which anatomical feature most strongly predisposes to primary angle-closure glaucoma?",o:["Deep anterior chamber","Long axial length","Shallow anterior chamber","Posterior lens dislocation","Enlarged corneal diameter"],a:2,e:"A shallow anterior chamber predisposes to crowding of the iridocorneal angle and increased risk of pupillary block with subsequent angle closure.<br><br>Long axial length (B) is more associated with myopia and open-angle glaucoma. Enlarged corneal diameter (E) is unrelated to angle crowding.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which precipitating factor commonly triggers acute angle-closure attack in predisposed patients?",o:["Bright sunlight","Dim illumination","Reading in daylight","Excess tearing","Hyperglycemia"],a:1,e:"Dim illumination physiologically dilates the pupil into the mid-dilated position where pupillary block becomes maximal, precipitating angle closure.<br><br>glaucoma emergency notes. Dim-light pupillary mid-dilation precipitating an attack is a frequently tested trigger.<br><br>Bright sunlight (A) usually causes miosis, which tends to reduce pupillary block risk. Excess tearing (D) does not precipitate angle closure.<br><br><em>(Recall and Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which slit-lamp finding is highly characteristic of acute angle-closure glaucoma?",o:["Deep anterior chamber","Keratic precipitates only","Shallow anterior chamber","Hypopyon","Iris coloboma"],a:2,e:"A shallow anterior chamber results from anterior bowing of the peripheral iris due to pupillary block and iris bombe formation.<br><br>Keratic precipitates (B) are more suggestive of anterior uveitis. Hypopyon (D) indicates severe inflammatory disease rather than primary angle closure.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which mechanism best explains colored halos around lights in acute angle closure?",o:["Retinal ischemia","Corneal epithelial edema","Vitreous hemorrhage","Lens subluxation","Optic nerve edema"],a:1,e:"Markedly elevated intraocular pressure disrupts corneal endothelial pump function, producing epithelial edema that diffracts light into colored halos.<br><br>Retinal ischemia (A) does not produce characteristic colored halos. Vitreous hemorrhage (C) typically causes floaters rather than halos.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which sign strongly differentiates acute angle closure from acute anterior uveitis?",o:["Red eye","Blurred vision","Mid-dilated fixed pupil","Photophobia","Circumcorneal congestion"],a:2,e:"The pupil in acute angle closure becomes mid-dilated and poorly reactive because iris ischemia impairs sphincter function.<br><br>Anterior uveitis typically produces a constricted irregular pupil due to ciliary spasm and posterior synechiae formation.<br><br>Both conditions may produce red eye (A) and circumcorneal congestion (E), making them less discriminatory.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which examination finding suggests extremely elevated IOP during acute angle closure?",o:["Soft globe","Stony hard eyeball","Pulsatile globe","Retinal detachment","Hyperdeep anterior chamber"],a:1,e:"Very high intraocular pressure produces a \"stony hard\" globe on digital palpation, a classic clinical finding in acute angle-closure glaucoma.<br><br>A soft globe (A) suggests ocular hypotony rather than acute glaucoma. Deep anterior chamber (E) contradicts angle-closure anatomy.<br><br><em>(Recall and Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which medication should generally be avoided before angle closure is relieved because it worsens pupillary block?",o:["Pilocarpine in severe iris ischemia","Timolol","Acetazolamide","Mannitol","Brimonidine"],a:0,e:"Pilocarpine may initially be ineffective or even worsen pupillary block when IOP is extremely high because ischemic iris sphincter muscles respond poorly.<br><br>IOP is usually lowered first with acetazolamide and hyperosmotics before pilocarpine becomes effective. Avoiding mydriatics before angle relief is a classic safety pitfall examiners highlight.<br><br>Timolol (B) and acetazolamide (C) help reduce aqueous production. Mannitol (D) rapidly lowers vitreous volume.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which chronic complication may follow repeated subacute angle-closure attacks?",o:["Macular hole","Peripheral anterior synechiae","Retinal detachment","Keratoconus","Dacryocystitis"],a:1,e:"Repeated appositional closure eventually leads to permanent adhesions between peripheral iris and trabecular meshwork, forming peripheral anterior synechiae (PAS).<br><br>PAS contributes to chronic angle-closure glaucoma.<br><br>Macular hole (A) and retinal detachment (C) are unrelated vitreoretinal disorders.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which procedure is both diagnostic and therapeutic in angle-closure glaucoma?",o:["Gonioscopy","Laser peripheral iridotomy","Schirmer testing","Automated perimetry","Keratometry"],a:1,e:"Laser peripheral iridotomy relieves pupillary block by creating an alternative aqueous pathway between posterior and anterior chambers.<br><br>Gonioscopy (A) is diagnostic but not therapeutic. Perimetry (D) evaluates visual fields rather than relieving block. Laser peripheral iridotomy being both diagnostic and definitive is an emphasised management fact.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which sign may indicate previous attacks of angle closure?",o:["Glaukomflecken","Roth spots","Macular drusen","Cherry-red spot","Papilledema"],a:0,e:"Glaukomflecken are small anterior subcapsular lens opacities produced by ischemic necrosis of lens epithelium during acute angle-closure attacks.<br><br>Roth spots (B) occur in infective endocarditis and hematologic disorders. Drusen (C) are associated with ARMD.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which symptom is least characteristic of acute angle closure?",o:["Vomiting","Colored halos","Severe ocular pain","Gradual painless field loss","Blurred vision"],a:3,e:"Gradual painless visual field loss is typical of chronic open-angle glaucoma rather than acute angle closure.<br><br>Acute angle closure presents dramatically with painful symptoms and sudden visual disturbance. Knowing which features are atypical for acute angle closure is a recurring discriminator question.<br><br>Vomiting (A), halos (B), and blurred vision (E) are classic acute angle-closure features.<br><br><em>(Recall and Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which pathophysiologic event directly elevates IOP in acute angle closure?",o:["Optic disc edema","Blocked trabecular outflow by peripheral iris","Excess vitreous production","Corneal dehydration","Retinal artery occlusion"],a:1,e:"Angle closure occurs when peripheral iris obstructs the trabecular meshwork, abruptly blocking aqueous outflow and rapidly increasing IOP.<br><br>This mechanism forms the core pathophysiology.<br><br>Optic disc edema (A) is a consequence of raised intracranial pressure rather than the primary mechanism of angle closure.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which lens-related factor contributes to primary angle closure in elderly patients?",o:["Lens flattening","Posterior lens displacement","Progressive lens thickening","Lens coloboma","Aphakia"],a:2,e:"Age-related increase in lens thickness pushes the iris anteriorly and narrows the angle, increasing pupillary block risk.<br><br>This mechanism is. Lens thickening and forward movement in elderly angle closure is a recurring mechanism question.<br><br>Aphakia (E) usually deepens the anterior chamber rather than promoting primary angle closure.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which visual acuity pattern is typical during acute angle-closure attack?",o:["Usually unaffected","Mild reduction only","Sudden marked reduction","Permanent no light perception initially","Isolated near vision loss only"],a:2,e:"Acute angle closure produces sudden marked visual reduction due to corneal edema, optic nerve dysfunction, and elevated intraocular pressure.<br><br>Permanent no light perception (D) is uncommon at initial presentation if treated promptly.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which group has particularly high prevalence of primary angle-closure glaucoma globally?",o:["Elderly Asian females","Young Caucasian myopes","African teenage males","Pediatric aphakic patients","Athletes only"],a:0,e:"Primary angle-closure glaucoma has particularly high prevalence among Asian populations, especially elderly females with hyperopic anatomy.<br><br>Young myopes (B) are more associated with retinal detachment and open-angle glaucoma rather than angle closure.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which emergency treatment rapidly dehydrates the vitreous body?",o:["Timolol","Pilocarpine","Mannitol","Brimonidine","Dorzolamide"],a:2,e:"Intravenous mannitol creates an osmotic gradient that draws fluid from the vitreous into plasma, rapidly lowering intraocular pressure.<br><br>Timolol (A) lowers aqueous production but does not rapidly dehydrate vitreous humor.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which condition may mimic acute angle-closure glaucoma but usually has low IOP instead?",o:["Acute anterior uveitis","Chronic open-angle glaucoma","Normal tension glaucoma","Congenital glaucoma","Ocular hypertension"],a:0,e:"Anterior uveitis may produce painful red eye and photophobia similar to angle closure, but IOP is often low initially because ciliary body inflammation reduces aqueous production.<br><br>Open-angle glaucoma (B) is generally painless and chronic. Ocular hypertension (E) lacks inflammatory symptoms.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which anatomical configuration is characteristic of plateau iris syndrome?",o:["Deep peripheral chamber angle","Flat iris with open ciliary body","Aphakic deep chamber","Posterior lens dislocation","Anteriorly positioned ciliary processes"],a:4,e:"Plateau iris syndrome occurs because anteriorly positioned ciliary processes push the peripheral iris forward despite relatively normal central chamber depth.<br><br>Posterior lens dislocation (D) deepens rather than narrows the chamber angle.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which statement regarding acute angle-closure glaucoma is most accurate?",o:["It resolves permanently after medical therapy alone","It is a painless chronic disease","Fellow eye carries high future risk","Gonioscopy has no role","Hypermetropia is protective"],a:2,e:"The fellow eye usually has similar anatomical predisposition and therefore carries substantial risk for future angle-closure attacks.<br><br>Prophylactic laser peripheral iridotomy is therefore commonly recommended. Recognising the definitive statement about acute angle closure is a classic single-best-answer test.<br><br>Medical therapy alone (A) does not remove anatomical predisposition. Hypermetropia (E) increases rather than decreases risk.<br><br><em>(Recall and Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"A 64-year-old woman presents with severe ocular pain, vomiting, cloudy cornea, and IOP of 58 mmHg. After initial acetazolamide therapy, which medication should be added once IOP begins to fall to reverse pupillary block?",o:["Atropine","Tropicamide","Pilocarpine","Phenylephrine","Cyclopentolate"],a:2,e:"Pilocarpine induces miosis, pulling the peripheral iris away from the trabecular meshwork and helping relieve pupillary block once ischemic iris sphincter function recovers.<br><br>Pilocarpine is usually ineffective initially when IOP is extremely high because the iris sphincter becomes ischemic.<br><br>Atropine (A), tropicamide (B), and cyclopentolate (E) worsen angle closure by inducing mydriasis.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which optic nerve change indicates chronic damage after repeated angle-closure attacks?",o:["Papilledema","Gliosis without cupping","Macular edema","Optic disc drusen","Glaucomatous optic disc cupping"],a:4,e:"Repeated or prolonged angle-closure attacks damage retinal ganglion cell axons, eventually producing glaucomatous optic disc cupping similar to chronic POAG.<br><br>Papilledema (A) results from raised intracranial pressure rather than glaucoma. Disc drusen (D) are calcified deposits unrelated to elevated IOP damage.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which test is most important before pharmacologic pupil dilation in elderly hyperopic patients?",o:["Gonioscopy","Schirmer testing","OCT macula","Color vision testing","Exophthalmometry"],a:0,e:"Gonioscopy evaluates anterior chamber angle anatomy and is essential before dilating pupils in patients at risk for angle closure.<br><br>Mydriasis may precipitate acute angle closure in susceptible individuals.<br><br>OCT macula (C) evaluates retinal structure rather than angle anatomy. Schirmer testing (B) assesses tear production only.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which symptom pattern most strongly suggests subacute angle closure rather than acute complete attack?",o:["Permanent severe vision loss","Intermittent halos and mild headache","Sudden total blindness","Profound photophobia only","Persistent floaters"],a:1,e:"Subacute or intermittent angle closure produces transient episodes of mild headache, blurred vision, and colored halos that resolve spontaneously.<br><br>Persistent floaters (E) suggest vitreoretinal pathology. Sudden total blindness (C) is uncommon in intermittent angle closure. Intermittent blurring with haloes suggesting subacute closure is an emphasised early-warning pattern.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which angle structure becomes permanently damaged in chronic angle-closure glaucoma?",o:["Corneal epithelium","Peripheral iris and trabecular meshwork","Lens nucleus","Vitreous cortex","Retina only"],a:1,e:"Permanent peripheral anterior synechiae form between peripheral iris and trabecular meshwork, producing irreversible angle obstruction in chronic angle closure.<br><br>This mechanism explains why some patients continue to have elevated IOP despite relief of pupillary block.<br><br>Corneal epithelium (A) may develop edema acutely but is not the primary site of chronic permanent obstruction.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which drug combination is most appropriate in initial acute angle-closure management?",o:["Atropine and phenylephrine","Timolol and acetazolamide","Tropicamide and cyclopentolate","Cycloplegics only","Mydriatics only"],a:1,e:"Timolol decreases aqueous production while acetazolamide rapidly suppresses aqueous secretion systemically, making this combination important in emergency IOP reduction.<br><br>Atropine (A) and tropicamide (C) worsen pupillary block by dilating the pupil. The combination regimen for initial acute angle-closure control is a heavily tested management sequence.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which feature most strongly favors acute angle closure over conjunctivitis?",o:["Red eye only","Watering","Markedly elevated IOP with corneal haze","Mild irritation","Mucoid discharge"],a:2,e:"Acute angle closure causes severe IOP elevation with corneal edema and cloudy vision, unlike conjunctivitis where intraocular pressure remains normal.<br><br>This distinction is highly important because acute angle closure is vision-threatening and. Features favouring angle closure over conjunctivitis is a recurring differentiation question.<br><br>Mucoid discharge (E) is much more characteristic of conjunctivitis than glaucoma. Mild irritation (D) does not explain acute severe symptoms.<br><br><em>(Recall and Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which finding may be seen on indentation gonioscopy in appositional angle closure?",o:["Angle cannot reopen","Angle widens temporarily","Trabecular destruction only","Complete absence of iris","Retinal tears"],a:1,e:"Indentation gonioscopy can transiently push aqueous into the periphery and separate appositional closure, distinguishing it from permanent synechial closure.<br><br>Permanent synechial closure (A) will not open significantly with indentation. Retinal tears (E) are unrelated findings. Indentation gonioscopy revealing appositional closure is an emphasised dynamic-assessment technique.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which symptom is produced by trigeminal nerve stimulation during acute angle closure?",o:["Floaters","Nausea and vomiting","Diplopia","Ptosis","Metamorphopsia"],a:1,e:"Severe ocular pain and trigeminal stimulation during acute angle closure activate autonomic pathways, producing nausea and vomiting.<br><br>Floaters (A) usually indicate vitreoretinal pathology. Metamorphopsia (E) suggests macular disease rather than glaucoma. Trigeminal-mediated nausea and vomiting in an acute attack is a classic mechanism correlate.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which statement regarding plateau iris syndrome is most accurate?",o:["It always resolves after iridotomy alone","Central anterior chamber is extremely shallow","Angle closure persists despite patent iridotomy","It occurs only in aphakia","It is caused by retinal pathology"],a:2,e:"In plateau iris syndrome, anteriorly positioned ciliary processes continue to crowd the angle even after pupillary block is relieved with iridotomy.<br><br>Patients may therefore require additional therapy such as laser iridoplasty.<br><br>The central anterior chamber may appear relatively normal, making option B incorrect. Retinal disease (E) has no causal role.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 4-month-old infant presents with excessive tearing, photophobia, and eyelid squeezing. Examination shows enlarged cloudy corneas. Which diagnosis is most likely?",o:["Congenital nasolacrimal duct obstruction","Congenital cataract","Retinoblastoma","Congenital glaucoma","Retinopathy of prematurity"],a:3,e:"The classic triad of congenital glaucoma is epiphora, photophobia, and blepharospasm. Elevated intraocular pressure stretches the infantile eye, producing enlarged cloudy corneas and buphthalmos.<br><br>Nasolacrimal duct obstruction (A) causes watering but does not enlarge the cornea or produce raised IOP. Congenital cataract (B) causes leukocoria rather than buphthalmos.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which developmental abnormality is primarily responsible for primary congenital glaucoma?",o:["Failure of retinal vascularization","Persistent pupillary membrane","Lens coloboma","Trabeculodysgenesis","Retinal dysplasia"],a:3,e:"Primary congenital glaucoma results from developmental malformation of the trabecular meshwork and anterior chamber angle, impairing aqueous drainage.<br><br>This embryologic mechanism is.<br><br>Persistent pupillary membrane (B) is a benign embryologic remnant unrelated to glaucoma pathogenesis. Retinal dysplasia (E) affects retinal development rather than aqueous outflow.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which corneal diameter strongly suggests congenital glaucoma in a newborn?",o:["8 mm","9 mm","10 mm","More than 12 mm","Less than 7 mm"],a:3,e:"A corneal diameter greater than 12 mm in infancy strongly suggests congenital glaucoma because elevated IOP stretches the elastic infantile globe.<br><br>Smaller corneal diameters (A, B) are within normal neonatal ranges and do not strongly indicate buphthalmos.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which corneal finding is classically associated with congenital glaucoma?",o:["Keratic precipitates","Arcus senilis","Band keratopathy","Haab striae","Corneal guttata"],a:3,e:"Haab striae are horizontal breaks in Descemet membrane caused by stretching from elevated intraocular pressure in congenital glaucoma.<br><br>Keratic precipitates (A) indicate uveitis. Arcus senilis (B) occurs in elderly patients and is unrelated to congenital glaucoma.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which symptom is least likely in congenital glaucoma?",o:["Photophobia","Blepharospasm","Epiphora","Severe purulent discharge","Corneal haze"],a:3,e:"Congenital glaucoma classically causes epiphora, photophobia, blepharospasm, and corneal edema, but purulent discharge suggests infectious conjunctivitis instead.<br><br>Corneal haze (E) results from endothelial dysfunction secondary to elevated IOP. Photophobia (A) occurs because corneal edema increases light sensitivity.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which surgical procedure is commonly preferred when cornea is relatively clear in congenital glaucoma?",o:["Trabeculectomy","Goniotomy","DCR","Vitrectomy","Penetrating keratoplasty"],a:1,e:"Goniotomy incises abnormal trabecular tissue under gonioscopic visualization and is preferred when the cornea is sufficiently clear.<br><br>Trabeculectomy (A) may be required in resistant cases but is not the classic initial surgery with clear cornea.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which globe abnormality develops because infantile sclera is distensible?",o:["Phthisis bulbi","Enophthalmos","Microphthalmos","Buphthalmos","Nanophthalmos"],a:3,e:"Elevated intraocular pressure stretches the elastic sclera and cornea of infants, producing enlarged globes termed buphthalmos.<br><br>Microphthalmos (C) refers to abnormally small eyes rather than enlarged glaucomatous globes.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which sign strongly differentiates congenital glaucoma from congenital nasolacrimal duct obstruction?",o:["Watering","Photophobia","Intermittent discharge","Mild lid crusting","Raised intraocular pressure"],a:4,e:"Raised intraocular pressure with corneal enlargement and haze strongly differentiates congenital glaucoma from nasolacrimal duct obstruction.<br><br>Watering (A) occurs in both disorders, making it less discriminatory. Mild discharge (D) may accompany duct obstruction but not explain enlarged cornea.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which anesthesia consideration is important during IOP measurement in infants?",o:["Crying may falsely elevate IOP","Sleeping lowers IOP permanently","Corneal size becomes irrelevant","General anesthesia prevents all errors","Tonometry is contraindicated"],a:0,e:"Infant crying and squeezing markedly elevate intraocular pressure measurements, complicating accurate tonometry in congenital glaucoma assessment.<br><br>General anesthesia (D) may facilitate examination but does not completely eliminate all measurement variability.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which angle surgery is preferred when corneal opacity prevents visualization of the angle?",o:["Goniotomy","Cyclocryotherapy","DCR","Trabeculotomy","Iridotomy"],a:3,e:"Trabeculotomy approaches Schlemm canal externally and is preferred when corneal haze prevents adequate gonioscopic visualization required for goniotomy.<br><br>Goniotomy (A) requires a sufficiently clear cornea for direct angle visualization. Iridotomy (E) is primarily used in angle-closure glaucoma.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which optic nerve finding may occur in congenital glaucoma?",o:["Papilledema only","Reversible optic disc cupping early","Cherry-red spot","Macular star","Roth spots"],a:1,e:"Unlike adult glaucoma, early optic disc cupping in infants may partially reverse after successful IOP control because infantile scleral tissues are elastic.<br><br>Papilledema (A) results from raised intracranial pressure rather than congenital glaucoma. Roth spots (E) are unrelated retinal hemorrhagic lesions.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which inheritance pattern is commonly associated with primary congenital glaucoma?",o:["X-linked dominant","X-linked recessive","Mitochondrial","Autosomal recessive","Autosomal dominant only"],a:3,e:"Primary congenital glaucoma frequently demonstrates autosomal recessive inheritance, especially in populations with consanguinity.<br><br>X-linked inheritance patterns (A, D) are not the classic inheritance mode for primary congenital glaucoma.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which clinical feature results directly from corneal edema in congenital glaucoma?",o:["Leukocoria","Diplopia","Proptosis","Photophobia","Ptosis"],a:3,e:"Corneal edema scatters incoming light and increases corneal sensitivity, producing marked photophobia in infants with congenital glaucoma.<br><br>Photophobia combined with epiphora and blepharospasm forms the classic triad.<br><br>Leukocoria (A) suggests cataract or retinoblastoma rather than congenital glaucoma. Proptosis (C) is unrelated.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which tonometry method is commonly used in infants under anesthesia?",o:["Schiotz tonometry only","Gonioscopy only","Hess charting","Perkins applanation tonometry","Keratometry"],a:3,e:"Portable Perkins applanation tonometry is commonly used during examination under anesthesia in infants with suspected congenital glaucoma.<br><br>Gonioscopy (B) evaluates angle anatomy but does not directly measure intraocular pressure. Hess charting (C) assesses ocular motility.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which age group most commonly presents with primary congenital glaucoma?",o:["Elderly patients","School-age children only","Birth to 3 years","Adolescents only","Adults in third decade"],a:2,e:"Primary congenital glaucoma most commonly presents during infancy and early childhood because developmental angle abnormalities impair aqueous outflow from birth.<br><br>Most cases become evident within the first year of life. The infantile onset age of primary congenital glaucoma is a recurring epidemiology fact.<br><br>Adult presentation (E) suggests juvenile or adult glaucoma rather than congenital disease.<br><br><em>(Recall and Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which finding is most characteristic of advanced untreated congenital glaucoma?",o:["Small cornea","Buphthalmos with corneal scarring","Dry eye syndrome","Retinal detachment only","Optic neuritis"],a:1,e:"Chronic elevated IOP enlarges the globe and causes persistent corneal edema leading to scarring and severe visual impairment.<br><br>Small cornea (A) contradicts the stretching effects of elevated infantile IOP. Optic neuritis (E) is unrelated inflammatory optic neuropathy.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which structure develops breaks forming Haab striae?",o:["Bowman membrane","Retina","Lens capsule","Descemet membrane","Sclera"],a:3,e:"Haab striae represent breaks in Descemet membrane caused by stretching from elevated intraocular pressure in congenital glaucoma.<br><br>Bowman membrane (A) is affected in superficial corneal pathology rather than congenital glaucoma stretching.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which feature most strongly favors congenital glaucoma over congenital conjunctivitis?",o:["Watering","Red eye","Enlarged corneal diameter","Lid swelling","Mild discharge"],a:2,e:"Enlarged corneal diameter strongly indicates buphthalmos from elevated IOP and helps differentiate congenital glaucoma from conjunctivitis.<br><br>Watering (A) and redness (B) may occur in both disorders and are therefore less specific.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which management principle is most accurate in congenital glaucoma?",o:["Medical therapy alone is usually curative","Observation is sufficient initially","Laser iridotomy is first-line treatment","Surgery is the definitive treatment","Steroids cure trabeculodysgenesis"],a:3,e:"Congenital glaucoma is primarily a surgical disease because developmental outflow abnormalities usually require anatomical correction.<br><br>Medical therapy may temporarily reduce IOP but definitive management typically involves goniotomy or trabeculotomy.<br><br>Laser iridotomy (C) treats pupillary block angle closure rather than trabeculodysgenesis. Steroids (E) do not correct developmental angle defects.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which statement regarding congenital glaucoma is most accurate?",o:["Corneal enlargement occurs because infant sclera is rigid","It usually presents after age 40 years","Optic disc cupping never reverses","Elevated IOP may enlarge the globe in infants","Hypermetropia is the primary cause"],a:3,e:"Infantile sclera and cornea are elastic, allowing elevated intraocular pressure to enlarge the globe and produce buphthalmos.<br><br>Early treatment may partially reverse optic disc cupping in infants.<br><br>Adult presentation (B) is inconsistent with congenital glaucoma. Optic disc cupping (C) may partially reverse after successful treatment in young children.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"A 6-month-old infant presents with bilateral watering, photophobia, and enlarged cloudy corneas. Which examination finding most strongly supports congenital glaucoma?",o:["Corneal diameter 9 mm","Corneal diameter 13 mm","Small shallow globes","Posterior synechiae","Macular cherry-red spot"],a:1,e:"Corneal diameter greater than 12 mm in infancy strongly suggests congenital glaucoma because elevated IOP stretches the elastic infantile cornea and sclera.<br><br>Corneal enlargement in infancy is a well-recognized clinical indicator of congenital glaucoma and reflects distensibility of the immature ocular coats under elevated intraocular pressure. Recognition of abnormal corneal diameter is essential in pediatric glaucoma assessment and is consistently emphasized in standard ophthalmology references. The classic epiphora, photophobia and blepharospasm triad in an infant is an instantly recognisable stem.<br><br>Posterior synechiae (D) are associated with anterior uveitis rather than congenital glaucoma. A 9 mm cornea (A) is within normal neonatal range and does not suggest buphthalmos.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which triad is classically associated with congenital glaucoma?",o:["Pain, redness, ptosis","Epiphora, photophobia, blepharospasm","Leukocoria, strabismus, nystagmus","Diplopia, headache, proptosis","Floaters, flashes, field loss"],a:1,e:"The classic congenital glaucoma triad consists of excessive tearing, photophobia, and blepharospasm due to corneal edema and elevated intraocular pressure.<br><br>The triad of epiphora, photophobia, and blepharospasm represents the classic clinical presentation of congenital glaucoma and results primarily from corneal edema secondary to elevated intraocular pressure. This constellation of findings is considered fundamental in pediatric ophthalmology diagnosis.<br><br>Leukocoria and strabismus (C) are more characteristic of retinoblastoma or congenital cataract. Floaters and flashes (E) are vitreoretinal symptoms not expected in infants.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which corneal abnormality represents breaks in Descemet membrane in congenital glaucoma?",o:["Vogt striae","Haab striae","Hudson-Stähli line","Fleischer ring","Kayser-Fleischer ring"],a:1,e:"Haab striae are horizontal or curvilinear breaks in Descemet membrane caused by stretching of the cornea due to elevated intraocular pressure.<br><br>Haab striae are important ophthalmic signs of congenital glaucoma and arise from stretching-induced breaks in Descemet membrane due to chronically elevated intraocular pressure during infancy. Their identification assists in establishing longstanding disease. Haab striae as horizontal Descemet breaks are a classic congenital-glaucoma sign examiners reuse.<br><br>Vogt striae (A) are vertical stromal stress lines seen in keratoconus. Kayser-Fleischer rings (E) occur in Wilson disease.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which feature most strongly differentiates congenital glaucoma from congenital nasolacrimal duct obstruction?",o:["Watering","Mild discharge","Enlarged cornea","Lid crusting","Tearing while crying"],a:2,e:"Corneal enlargement with increased diameter strongly favors congenital glaucoma because elevated infantile IOP stretches the globe.<br><br>Corneal enlargement is a significant differentiating feature because congenital glaucoma causes distension of the elastic infantile globe, whereas congenital nasolacrimal duct obstruction does not alter corneal dimensions or intraocular pressure.<br><br>Watering (A) may occur in both conditions and therefore lacks specificity. Mild discharge (B) is more suggestive of nasolacrimal duct obstruction.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which surgical procedure is preferred when the cornea is sufficiently clear in congenital glaucoma?",o:["Trabeculectomy","Cyclophotocoagulation","Iridotomy","DCR","Goniotomy"],a:4,e:"Goniotomy is preferred when corneal clarity allows gonioscopic visualization of the angle because abnormal trabecular tissue can be incised directly.<br><br>Goniotomy remains an established primary surgical procedure for congenital glaucoma when corneal clarity permits visualization of the anterior chamber angle. The procedure directly addresses abnormal trabecular tissue responsible for impaired aqueous drainage.<br><br>Trabeculectomy (A) is usually reserved for refractory cases. Iridotomy (C) treats pupillary block angle closure rather than congenital glaucoma.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which structure is primarily malformed in primary congenital glaucoma?",o:["Retina","Lens capsule","Trabecular meshwork","Corneal epithelium","Optic chiasm"],a:2,e:"Primary congenital glaucoma results from trabeculodysgenesis causing impaired aqueous drainage through the malformed anterior chamber angle.<br><br>Developmental malformation of the trabecular meshwork and anterior chamber angle forms the primary pathogenic basis of congenital glaucoma and results in impaired aqueous humor outflow from early life.<br><br>The retina (A) and optic chiasm (E) are not primary sites of pathology in congenital glaucoma. Corneal edema develops secondarily from raised IOP.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which optic nerve feature in congenital glaucoma may partially reverse after treatment?",o:["Disc hemorrhage","Optic atrophy","Disc drusen","Papilledema","Optic disc cupping"],a:4,e:"Because infantile scleral tissues are elastic, early glaucomatous optic disc cupping may partially reverse after successful IOP control.<br><br>Partial reversal of optic disc cupping may occur in infants following successful intraocular pressure control because pediatric ocular connective tissues retain considerable elasticity during early childhood.<br><br>Optic atrophy (B) generally represents irreversible damage. Papilledema (D) reflects raised intracranial pressure rather than congenital glaucoma.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which condition commonly causes buphthalmos?",o:["Congenital cataract","Persistent fetal vasculature","Retinoblastoma","Congenital glaucoma","Optic neuritis"],a:3,e:"Buphthalmos refers to enlargement of the infantile globe due to elevated intraocular pressure and is classically associated with congenital glaucoma.<br><br>Buphthalmos represents enlargement of the infantile globe secondary to chronically elevated intraocular pressure and is regarded as a characteristic manifestation of congenital glaucoma.<br><br>Congenital cataract (A) causes leukocoria without globe enlargement. Retinoblastoma (C) may enlarge the globe late but is not the classic cause of buphthalmos.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which inheritance pattern is commonly associated with primary congenital glaucoma?",o:["Autosomal recessive","X-linked dominant","X-linked recessive","Mitochondrial","Autosomal dominant only"],a:0,e:"Primary congenital glaucoma often demonstrates autosomal recessive inheritance, especially in communities with consanguineous marriages.<br><br>Primary congenital glaucoma frequently demonstrates autosomal recessive inheritance, particularly in populations with higher rates of consanguinity, making family history clinically relevant during evaluation.<br><br>X-linked inheritance patterns (B, C) are not the classic inheritance mode of primary congenital glaucoma.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which tonometric issue is especially important during examination of infants?",o:["Corneal edema lowers IOP permanently","IOP is always normal during anesthesia","Tonometry cannot be performed in infants","Crying may falsely elevate IOP","Tonometry is contraindicated"],a:3,e:"Crying and squeezing elevate intraocular pressure measurements in infants and may complicate accurate congenital glaucoma assessment.<br><br>Accurate intraocular pressure measurement in infants may be challenging because crying, eyelid squeezing, and agitation can produce falsely elevated readings during examination.<br><br>Tonometry (C, E) is feasible using handheld devices under careful conditions. Anesthesia (B) does not eliminate all variability.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which surgical procedure is preferred when corneal opacity prevents angle visualization?",o:["Goniotomy","Trabeculotomy","LASIK","Iridotomy","DSEK"],a:1,e:"Trabeculotomy approaches Schlemm canal externally and is preferred when corneal haze prevents gonioscopic visualization needed for goniotomy.<br><br>Trabeculotomy is preferred in cases with significant corneal haze because the procedure allows external access to Schlemm canal without requiring direct visualization of the anterior chamber angle.<br><br>Goniotomy (A) requires a clear enough cornea to visualize the angle directly. LASIK (C) has no role in pediatric glaucoma.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which age group most commonly presents with primary congenital glaucoma?",o:["Neonates and infants","Teenagers only","Middle-aged adults","Elderly patients","School-age children only"],a:0,e:"Most congenital glaucoma cases present within the first year of life because aqueous drainage abnormalities are present from birth.<br><br>Most patients with primary congenital glaucoma present within the first year of life because aqueous outflow abnormalities are present from birth and rapidly affect the developing eye. The typical infantile age of primary congenital glaucoma onset is a recurring epidemiology fact.<br><br>Middle-aged adults (C) usually develop open-angle glaucoma rather than congenital glaucoma.<br><br><em>(Recall and Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which corneal appearance is expected in congenital glaucoma?",o:["Crystal clear microcornea","Arcus senilis","Peripheral ulceration","Corneal edema and haze","Keratic precipitates only"],a:3,e:"Elevated intraocular pressure impairs endothelial function, causing corneal edema and haziness in congenital glaucoma.<br><br>Corneal edema in congenital glaucoma results from endothelial dysfunction caused by elevated intraocular pressure and contributes significantly to visual impairment and photophobia in affected infants.<br><br>Arcus senilis (B) occurs in elderly adults. Keratic precipitates (E) suggest uveitis rather than congenital glaucoma.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which finding most strongly supports diagnosis of congenital glaucoma rather than megalocornea?",o:["Large cornea with normal IOP","Deep anterior chamber","Bilateral clear corneas","Raised IOP with optic disc cupping","Stable vision"],a:3,e:"Megalocornea produces large corneas without elevated IOP or glaucomatous optic neuropathy, unlike congenital glaucoma.<br><br>The presence of elevated intraocular pressure with optic disc cupping distinguishes congenital glaucoma from megalocornea, which is characterized by enlarged corneas without glaucomatous optic neuropathy.<br><br>Large corneas alone (A) may occur in both conditions. Deep chambers (B) do not establish glaucomatous pathology.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which sign is most likely to persist into adulthood after childhood congenital glaucoma?",o:["Haab striae","Hypopyon","Corneal ulcer","Papilledema","Vitreous hemorrhage"],a:0,e:"Haab striae may remain visible into adulthood as evidence of prior Descemet membrane stretching during congenital glaucoma.<br><br>Haab striae may remain visible long after childhood and serve as permanent structural evidence of prior corneal stretching caused by elevated intraocular pressure during infancy.<br><br>Hypopyon (B) and vitreous hemorrhage (E) are unrelated inflammatory or retinal findings.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which symptom results primarily from corneal edema in congenital glaucoma?",o:["Photophobia","Ptosis","Diplopia","Proptosis","Nyctalopia"],a:0,e:"Corneal edema scatters light and increases light sensitivity, producing marked photophobia in infants with congenital glaucoma.<br><br>Photophobia develops primarily because corneal edema scatters incoming light and increases ocular sensitivity, making it an important clinical manifestation of congenital glaucoma.<br><br>Diplopia (C) and proptosis (D) are not characteristic manifestations of congenital glaucoma.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which mechanism produces enlargement of the infantile globe in congenital glaucoma?",o:["Vitreous inflammation","Retinal ischemia","Corneal ulceration","Scleral elasticity with elevated IOP","Lens displacement"],a:3,e:"The infantile sclera is elastic and stretches under chronically elevated intraocular pressure, producing buphthalmos.<br><br>The elastic nature of the infantile sclera allows progressive enlargement of the globe under sustained elevated intraocular pressure, resulting in the characteristic appearance of buphthalmos.<br><br>Retinal ischemia (B) and lens displacement (E) do not explain globe enlargement.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which condition is an important differential diagnosis of congenital glaucoma with tearing in infants?",o:["Retinitis pigmentosa","Nasolacrimal duct obstruction","Macular degeneration","Optic neuritis","CRAO"],a:1,e:"Both congenital glaucoma and nasolacrimal duct obstruction produce tearing, but congenital glaucoma additionally causes photophobia, corneal enlargement, and raised IOP.<br><br>Congenital nasolacrimal duct obstruction is an important differential diagnosis because both conditions may present with tearing; however, congenital glaucoma additionally produces photophobia, corneal enlargement, and elevated intraocular pressure.<br><br>Macular degeneration (C) and CRAO (E) occur in adults rather than infants.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which management principle is most accurate in congenital glaucoma?",o:["Observation alone is preferred","Medical therapy is definitive","Surgery is primary treatment","Laser iridotomy is always first-line","Steroids cure trabeculodysgenesis"],a:2,e:"Congenital glaucoma is primarily treated surgically because developmental angle abnormalities require anatomical correction.<br><br>Surgical intervention constitutes the definitive management of congenital glaucoma because developmental abnormalities of aqueous outflow pathways usually cannot be adequately corrected with medical therapy alone.<br><br>Medical therapy may temporarily reduce IOP but is rarely definitive alone. Steroids (E) do not correct angle dysgenesis.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which statement regarding congenital glaucoma is most accurate?",o:["It usually presents after age 40","Corneal enlargement is impossible in infancy","It is always unilateral","Hypermetropia is the primary mechanism","Elevated IOP may produce Haab striae"],a:4,e:"Raised intraocular pressure stretches Descemet membrane and produces Haab striae, a classic sign of congenital glaucoma.<br><br>Haab striae develop as a consequence of stretching-induced breaks in Descemet membrane caused by elevated intraocular pressure and are considered characteristic ocular findings in congenital glaucoma.<br><br>Congenital glaucoma commonly presents in infancy rather than adulthood. Bilateral disease is frequent, making option E incorrect.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 5-month-old infant has bilateral cloudy enlarged corneas, photophobia, and excessive tearing. Fundoscopy reveals optic disc cupping. Which feature most strongly favors congenital glaucoma over congenital hereditary endothelial dystrophy?",o:["Corneal haze","Epiphora","Elevated intraocular pressure","Bilateral involvement","Photophobia"],a:2,e:"Both congenital glaucoma and congenital hereditary endothelial dystrophy may present with cloudy corneas and photophobia, but elevated intraocular pressure with buphthalmos strongly favors congenital glaucoma.<br><br>Although both congenital glaucoma and congenital hereditary endothelial dystrophy may produce bilateral corneal haze, elevated intraocular pressure with globe enlargement strongly supports the diagnosis of congenital glaucoma. The infant with cloudy enlarged corneas, photophobia and tearing is a classic buphthalmos stem.<br><br>Corneal haze (A) and bilateral involvement (D) may occur in both disorders, making them less discriminatory findings.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which corneal measurement is considered highly suspicious for congenital glaucoma in a 1-year-old child?",o:["10 mm","10.5 mm","11 mm","13 mm","9 mm"],a:3,e:"Corneal diameter exceeding 12 mm after infancy strongly suggests congenital glaucoma because elevated IOP enlarges the elastic infantile cornea.<br><br>Corneal diameter exceeding 12 mm after infancy is considered highly suggestive of congenital glaucoma because elevated intraocular pressure enlarges the elastic infantile cornea. A corneal diameter above the buphthalmos threshold is a classic measured-sign question.<br><br>Measurements around 10-11 mm (A-C) are closer to normal pediatric ranges and are less suggestive of buphthalmos.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which structure is directly visualized during goniotomy for congenital glaucoma?",o:["Retina","Lens equator","Trabecular meshwork","Vitreous base","Optic chiasm"],a:2,e:"Goniotomy involves direct incision of abnormal trabecular tissue under gonioscopic visualization to improve aqueous outflow.<br><br>Goniotomy involves direct surgical incision of abnormal trabecular tissue under gonioscopic visualization in order to improve aqueous humor outflow through the anterior chamber angle.<br><br>The retina (A) and vitreous base (D) are unrelated posterior segment structures not targeted during angle surgery.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which factor explains why congenital glaucoma enlarges the globe while adult glaucoma usually does not?",o:["Stronger adult corneal endothelium","Larger infant optic disc","Increased vitreous production","Elastic infantile sclera","Greater aqueous secretion in infancy"],a:3,e:"The infantile sclera and cornea are highly elastic and stretch under elevated IOP, producing buphthalmos. Adult sclera is more rigid and resists enlargement.<br><br>The infantile sclera possesses substantial elasticity and therefore enlarges under elevated intraocular pressure, whereas the adult sclera is comparatively rigid and resists distension.<br><br>Greater aqueous secretion (E) does not primarily explain globe enlargement. Optic disc size (B) is unrelated to buphthalmos formation.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which refractive error commonly develops in congenital glaucoma because of increased axial length?",o:["Hypermetropia","High myopia","Astigmatism only","Presbyopia","Emmetropia"],a:1,e:"Stretching of the infantile globe increases axial length and commonly produces myopia in congenital glaucoma.<br><br>Axial elongation caused by chronically elevated intraocular pressure commonly produces myopia in congenital glaucoma because enlargement of the globe increases axial length. The myopic shift from buphthalmic globe enlargement is a frequently tested congenital-glaucoma correlate.<br><br>Hypermetropia (A) is more associated with short axial length and angle-closure glaucoma rather than buphthalmos.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which optic disc feature in congenital glaucoma indicates successful early treatment response?",o:["Progressive papilledema","Macular edema","Development of drusen","Partial reversal of cupping","Persistent hemorrhages"],a:3,e:"Early optic disc cupping in infants may partially reverse after IOP normalization because pediatric connective tissues remain elastic.<br><br>Partial reversal of optic disc cupping following successful treatment reflects the elastic properties of infantile ocular tissues and may indicate effective reduction of intraocular pressure.<br><br>Papilledema (A) reflects raised intracranial pressure rather than congenital glaucoma improvement. Persistent hemorrhages (E) are not expected therapeutic indicators.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which condition may closely mimic congenital glaucoma because of watering and photophobia?",o:["Congenital cataract","Retinoblastoma","Retinal dystrophy","Optic nerve hypoplasia","Congenital nasolacrimal obstruction"],a:4,e:"Nasolacrimal duct obstruction commonly causes tearing in infants and may initially mimic congenital glaucoma, but corneal enlargement and elevated IOP are absent.<br><br>Congenital nasolacrimal duct obstruction may clinically resemble congenital glaucoma because both conditions can produce tearing in infancy; however, glaucoma additionally causes corneal enlargement and raised intraocular pressure.<br><br>Congenital cataract (A) primarily causes leukocoria rather than epiphora with buphthalmos.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which anesthesia-related factor may falsely reduce IOP measurement during infant examination?",o:["Crying vigorously","Eyelid squeezing","Deep general anesthesia","Corneal edema","Blepharospasm"],a:2,e:"Deep general anesthesia may artificially lower measured intraocular pressure, potentially masking true glaucoma severity in infants.<br><br>Deep general anesthesia may artificially reduce measured intraocular pressure and therefore should be considered when interpreting examination findings in infants with suspected congenital glaucoma.<br><br>Crying (A) and squeezing (B) falsely elevate rather than reduce IOP measurements.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which statement regarding Haab striae is most accurate?",o:["They are retinal tears","They occur in Bowman layer","They are pathognomonic of keratoconus","They indicate optic nerve edema","They represent breaks in Descemet membrane"],a:4,e:"Haab striae are breaks in Descemet membrane caused by stretching of the cornea due to elevated intraocular pressure in congenital glaucoma.<br><br>Haab striae are linear breaks in Descemet membrane produced by stretching of the cornea secondary to elevated intraocular pressure in congenital glaucoma.<br><br>Bowman layer involvement (B) is more relevant to superficial corneal pathology. Keratoconus (C) is associated with Vogt striae instead.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which statement regarding congenital glaucoma management is most accurate?",o:["Long-term steroids are curative","Surgery should be delayed until school age","Early surgery improves visual prognosis","Laser iridotomy is definitive treatment in all cases","Observation is adequate in mild cases"],a:2,e:"Prompt surgical treatment reduces optic nerve damage, minimizes amblyopia risk, and improves long-term visual outcomes in congenital glaucoma.<br><br>Early surgical intervention is essential in congenital glaucoma because prompt intraocular pressure control reduces optic nerve damage, minimizes amblyopia risk, and improves long-term visual prognosis.<br><br>Observation alone (E) risks irreversible optic nerve damage and corneal scarring. Iridotomy (D) is mainly used in angle-closure glaucoma rather than trabeculodysgenesis.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which investigation is considered the gold standard for measurement of intraocular pressure in glaucoma evaluation?",o:["Schiotz tonometry","Non-contact tonometry","Rebound tonometry","Perkins tonometry","Goldmann applanation tonometry"],a:4,e:"Goldmann applanation tonometry remains the gold standard for intraocular pressure measurement because of its accuracy and reproducibility in glaucoma assessment.<br><br>Precise IOP assessment is fundamental in glaucoma diagnosis and follow-up, and Goldmann applanation tonometry continues to serve as the reference standard against which other tonometric techniques are compared.<br><br>Non-contact tonometry (B) is useful for screening but less accurate. Schiotz tonometry (A) may be affected by scleral rigidity and positioning errors.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which investigation is essential for differentiating open-angle glaucoma from angle-closure glaucoma?",o:["Pachymetry","Gonioscopy","OCT macula","Amsler grid","Hess charting"],a:1,e:"Gonioscopy directly visualizes the anterior chamber angle and is essential for classifying glaucoma as open-angle or angle-closure type.<br><br>Evaluation of angle anatomy is critical in glaucoma workup because management strategies differ significantly between open-angle and angle-closure mechanisms.<br><br>Pachymetry (A) measures corneal thickness but does not classify angle anatomy. OCT macula (C) evaluates retinal structure rather than the chamber angle.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which visual field defect is classically considered an early glaucomatous change?",o:["Central scotoma","Homonymous hemianopia","Nasal step","Bitemporal hemianopia","Total field loss"],a:2,e:"The nasal step occurs due to damage of arcuate retinal nerve fiber bundles and represents a classic early glaucomatous visual field defect.<br><br>Early glaucomatous field defects typically respect the horizontal meridian because retinal nerve fiber bundle loss follows characteristic anatomical pathways.<br><br>Homonymous hemianopia (B) indicates retrochiasmal neurological disease. Bitemporal hemianopia (D) suggests optic chiasmal pathology.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which investigation measures central corneal thickness in glaucoma patients?",o:["Keratometry","Retinoscopy","Perimetry","Pachymetry","Gonioscopy"],a:3,e:"Pachymetry measures central corneal thickness, which significantly influences interpretation of intraocular pressure measurements.<br><br>Corneal thickness assessment is important because thin corneas may underestimate true IOP while thick corneas may falsely elevate measured values.<br><br>Perimetry (C) evaluates visual field function rather than corneal thickness. Keratometry (A) measures corneal curvature.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which imaging modality is commonly used to assess retinal nerve fiber layer thickness in glaucoma?",o:["Fundus fluorescein angiography","CT orbit","B-scan ultrasonography","OCT","MRI brain"],a:3,e:"Optical coherence tomography (OCT) quantitatively evaluates retinal nerve fiber layer thickness and optic nerve head structure in glaucoma.<br><br>Structural assessment of retinal nerve fiber loss has become increasingly important because glaucomatous damage may be detected before obvious visual field defects appear.<br><br>FFA (A) evaluates retinal vascular circulation rather than nerve fiber thickness. B-scan ultrasonography (C) is mainly used for posterior segment imaging in opaque media.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which investigation is most useful for monitoring functional progression in glaucoma?",o:["Schirmer test","OCT anterior segment","Corneal topography","Automated perimetry","Fluorescein staining"],a:3,e:"Automated perimetry is the standard investigation for monitoring progression of glaucomatous visual field loss over time.<br><br>Functional assessment through serial visual field analysis remains essential in long-term glaucoma management because progressive field loss reflects ongoing optic nerve damage.<br><br>Corneal topography (C) evaluates corneal curvature and is unrelated to glaucoma progression monitoring. Schirmer testing (A) assesses tear production.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which optic disc feature is highly suggestive of glaucomatous damage?",o:["Disc edema","Increased cup-disc ratio","Cherry-red spot","Macular star","Retinal hemorrhage only"],a:1,e:"Progressive enlargement of the optic cup relative to disc size reflects loss of neuroretinal rim tissue in glaucoma.<br><br>Optic disc evaluation is a cornerstone of glaucoma diagnosis because structural optic nerve changes often precede advanced visual symptoms.<br><br>Disc edema (A) suggests raised intracranial pressure or optic neuritis rather than glaucoma. Cherry-red spot (C) occurs in retinal arterial occlusion.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which investigation is particularly useful for documenting optic disc changes over time?",o:["Fundus photography","Tonography","Keratometry","Electroretinography","Refraction"],a:0,e:"Serial optic disc photography provides objective documentation of structural glaucomatous progression over time.<br><br>Comparison of sequential optic nerve images assists in identifying progressive neuroretinal rim thinning, hemorrhages, and increasing cupping.<br><br>Tonography (B) measures aqueous outflow facility rather than documenting disc morphology. Electroretinography (D) assesses retinal electrical function.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which finding on gonioscopy indicates angle-closure glaucoma?",o:["Visible scleral spur throughout","Open trabecular meshwork","Peripheral iris obstructing trabecular meshwork","Deep anterior chamber angle","Wide ciliary body band"],a:2,e:"Angle closure occurs when peripheral iris obstructs the trabecular meshwork, preventing aqueous outflow.<br><br>Gonioscopy remains essential for direct assessment of angle anatomy and differentiation of appositional versus synechial closure. A closed angle on gonioscopy confirming the diagnosis is an emphasised confirmatory step.<br><br>Visible scleral spur (A) and wide ciliary body band (E) suggest open angles rather than angle closure.<br><br><em>(Recall and Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"Which visual field defect is strongly associated with glaucoma because it follows retinal nerve fiber bundle anatomy?",o:["Arcuate scotoma","Homonymous hemianopia","Junctional scotoma","Central hemianopia","Altitudinal defect only"],a:0,e:"Arcuate scotomas develop due to damage of arcuate retinal nerve fiber bundles and represent characteristic glaucomatous field loss.<br><br>These defects typically extend from the blind spot toward the nasal field while respecting the horizontal meridian.<br><br>Homonymous hemianopia (B) results from retrochiasmal neurological lesions rather than glaucomatous optic neuropathy.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which factor may falsely lower measured IOP during applanation tonometry?",o:["Thick cornea","Large pupil","Corneal edema only","Thin cornea","Cataract"],a:3,e:"Thin central corneal thickness may cause underestimation of true intraocular pressure during applanation tonometry.<br><br>Interpretation of measured IOP should therefore incorporate corneal thickness assessment to avoid underdiagnosis or undertreatment of glaucoma.<br><br>Thick cornea (A) tends to falsely elevate measured intraocular pressure rather than lower it. Cataract (E) does not significantly alter applanation readings.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which investigation primarily evaluates aqueous outflow facility?",o:["Tonography","OCT","Gonioscopy","Retinoscopy","Keratometry"],a:0,e:"Tonography assesses aqueous outflow facility by measuring the rate of intraocular pressure reduction under sustained applanation.<br><br>Although less commonly used today, tonography historically contributed to glaucoma diagnosis and evaluation of aqueous drainage abnormalities.<br><br>OCT (B) evaluates structural retinal and optic nerve changes rather than aqueous outflow function.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which optic disc hemorrhage is classically associated with glaucoma progression?",o:["Flame-shaped disc margin hemorrhage","Subhyaloid hemorrhage","Roth spot","Vitreous hemorrhage","Preretinal hemorrhage"],a:0,e:"Splinter or flame-shaped hemorrhages at the optic disc margin are strongly associated with active glaucomatous progression.<br><br>Disc hemorrhages may indicate ongoing retinal nerve fiber layer damage and require careful monitoring during glaucoma follow-up.<br><br>Roth spots (C) are associated with hematologic or infective disorders rather than glaucoma progression.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which investigation is most useful for detecting early structural glaucomatous damage before visual field loss becomes apparent?",o:["OCT retinal nerve fiber layer analysis","Schirmer testing","Color vision charting only","Hess charting","Corneal scraping"],a:0,e:"OCT retinal nerve fiber layer analysis can identify early glaucomatous structural damage before detectable functional visual field defects occur.<br><br>Early recognition of nerve fiber layer thinning allows earlier therapeutic intervention and improved long-term glaucoma management.<br><br>Schirmer testing (B) evaluates tear production rather than optic nerve structure. Hess charting (D) assesses ocular motility disorders.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which test is commonly used to assess glaucomatous visual field defects quantitatively?",o:["Ishihara chart","Hertel exophthalmometry","Maddox rod","Humphrey visual field analyzer","Amsler grid only"],a:3,e:"The Humphrey visual field analyzer is widely used for automated perimetry and quantitative assessment of glaucomatous visual field defects.<br><br>Automated perimetry provides reproducible analysis of progression and assists in therapeutic decision-making during glaucoma follow-up.<br><br>Ishihara charts (A) assess color vision rather than visual field defects. Maddox rod (C) evaluates ocular alignment.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which finding violates the ISNT rule in glaucomatous optic neuropathy?",o:["Inferior rim thicker than superior rim","Temporal rim thinner than nasal rim","Inferior rim thicker than nasal rim","Nasal rim thicker than temporal rim","Superior rim thinner than temporal rim"],a:4,e:"The normal ISNT rule states that neuroretinal rim thickness decreases in the order Inferior \\> Superior \\> Nasal \\> Temporal. Violation suggests glaucomatous damage.<br><br>Assessment of neuroretinal rim configuration is important during optic disc examination in glaucoma evaluation.<br><br>Options A, B, D, and E follow expected physiological rim relationships and therefore do not violate the ISNT rule.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which examination technique best assesses the depth of the anterior chamber angle clinically before gonioscopy?",o:["Van Herick technique","Schirmer test","Retinoscopy","Keratometry","Hess screen"],a:0,e:"The Van Herick technique estimates peripheral anterior chamber depth at the slit lamp and helps identify potentially occludable angles.<br><br>It serves as a rapid screening method before definitive gonioscopic examination of the angle.<br><br>Retinoscopy (C) assesses refractive status rather than chamber depth. Keratometry (D) measures corneal curvature.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which glaucoma investigation evaluates both structural and functional disease progression together most effectively?",o:["Tonometry alone","Corneal staining","Refraction only","Combined OCT and perimetry","Retinoscopy only"],a:3,e:"Combined structural assessment with OCT and functional evaluation with automated perimetry provides comprehensive glaucoma monitoring.<br><br>Correlation between retinal nerve fiber layer loss and visual field progression improves assessment of disease severity and therapeutic response.<br><br>Tonometry alone (A) cannot fully assess optic nerve damage progression. Refraction (C) is unrelated to glaucomatous monitoring.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which feature is most characteristic of glaucomatous optic disc cupping?",o:["Uniform disc pallor without excavation","Vertical enlargement of cup","Disc swelling with hemorrhage","Macular edema","Optic disc drusen"],a:1,e:"Glaucomatous cupping characteristically progresses vertically because superior and inferior retinal nerve fiber bundles are preferentially damaged.<br><br>Evaluation of vertical cup enlargement is essential during optic disc assessment in glaucoma diagnosis.<br><br>Disc swelling (C) indicates edema rather than glaucomatous excavation. Optic disc drusen (E) produce pseudopapilledema rather than typical cupping.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which statement regarding glaucoma investigations is most accurate?",o:["Tonometry alone confirms glaucoma diagnosis","Normal IOP excludes glaucoma completely","Glaucoma diagnosis requires structural and functional assessment","Gonioscopy has no role in open-angle glaucoma","Visual field testing is unnecessary in follow-up"],a:2,e:"Comprehensive glaucoma evaluation requires assessment of intraocular pressure, optic nerve structure, visual field function, and anterior chamber angle anatomy.<br><br>Accurate diagnosis and monitoring depend upon correlation of structural optic nerve changes with functional visual field findings over time.<br><br>Normal IOP (B) does not exclude normal tension glaucoma. Tonometry alone (A) is insufficient because optic nerve and visual field evaluation are essential.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 58-year-old man with suspected glaucoma has normal intraocular pressure but progressive optic disc cupping and paracentral scotomas. Which investigation is most useful to confirm structural progression?",o:["Schirmer testing","B-scan ultrasonography","Keratometry","OCT retinal nerve fiber layer analysis","Refraction"],a:3,e:"OCT retinal nerve fiber layer analysis objectively measures structural glaucomatous damage and is highly sensitive for detecting progression in normal tension glaucoma.<br><br>Structural assessment is especially important in patients whose intraocular pressure remains within statistically normal ranges despite progressive optic neuropathy.<br><br>Schirmer testing (A) evaluates tear production rather than optic nerve integrity. B-scan ultrasonography (B) is not routinely used for glaucomatous structural monitoring.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A patient with chronic angle-closure glaucoma undergoes gonioscopy. Which finding most strongly indicates permanent synechial closure rather than appositional closure?",o:["Angle opens on indentation","Trabecular meshwork becomes visible","Peripheral anterior synechiae","Deep anterior chamber centrally","Presence of scleral spur"],a:2,e:"Peripheral anterior synechiae represent permanent adhesions between peripheral iris and trabecular meshwork, indicating irreversible angle closure.<br><br>Distinguishing appositional from synechial closure is essential because permanent synechial obstruction often requires more aggressive glaucoma management. Distinguishing appositional from synechial closure on gonioscopy is a recurring viva theme.<br><br>Angles that reopen on indentation (A) indicate appositional rather than permanent closure. Visible scleral spur (E) suggests at least partial angle openness.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"A glaucoma suspect has asymmetric optic discs with cup-disc ratios of 0.3 and 0.7. Which additional finding most strongly supports glaucomatous optic neuropathy?",o:["Symmetric visual acuity","Hypermetropia","Mild nuclear cataract","Inferior neuroretinal rim thinning","Normal pupils"],a:3,e:"Localized thinning of the neuroretinal rim, particularly inferiorly or superiorly, strongly supports glaucomatous optic nerve damage.<br><br>Assessment of rim integrity is fundamental during optic disc evaluation because glaucomatous damage preferentially affects superior and inferior nerve fiber bundles.<br><br>Mild cataract (C) and refractive status (B) do not specifically confirm glaucomatous optic neuropathy.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A patient undergoing automated perimetry demonstrates unreliable visual field testing. Which parameter most strongly indicates poor test reliability?",o:["Mean deviation only","Pattern standard deviation only","Arcuate scotoma","Nasal step defect","High fixation losses"],a:4,e:"High fixation losses indicate poor patient fixation and reduce reliability of automated visual field interpretation.<br><br>Reliable perimetry requires stable fixation and consistent patient responses because inaccurate fields may mimic or obscure glaucoma progression.<br><br>Mean deviation (A) and pattern standard deviation (B) assess field defects rather than reliability. Nasal step (D) is a true glaucomatous defect.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"A patient with ocular hypertension has central corneal thickness of 620 microns. What is the most appropriate interpretation of measured IOP?",o:["True IOP is likely lower than measured","True IOP is likely higher than measured","Pachymetry has no influence on IOP","Glaucoma is excluded completely","Cornea is abnormally thin"],a:0,e:"Thick corneas produce falsely elevated applanation tonometry readings, causing measured intraocular pressure to overestimate true pressure.<br><br>Interpretation of intraocular pressure should therefore always consider corneal thickness during glaucoma evaluation.<br><br>Thin corneas (B, E) produce the opposite effect and may underestimate actual intraocular pressure.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 67-year-old patient with progressive glaucoma demonstrates splinter hemorrhage at the optic disc margin. What does this finding most strongly suggest?",o:["Stable disease","Active glaucomatous progression","Papilledema","Retinal artery occlusion","Diabetic maculopathy"],a:1,e:"Optic disc splinter hemorrhages are strongly associated with ongoing retinal nerve fiber layer loss and progressive glaucomatous damage.<br><br>Detection of disc hemorrhages warrants careful reassessment of intraocular pressure control and disease progression.<br><br>Papilledema (C) causes disc swelling rather than localized splinter hemorrhages typical of glaucoma.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A patient with advanced glaucoma complains of difficulty walking downstairs despite preserved central visual acuity. Which investigation best explains this complaint?",o:["OCT macula","Schirmer testing","Corneal pachymetry","Visual field analysis","Refraction"],a:3,e:"Peripheral visual field loss significantly impairs mobility and spatial awareness despite preservation of central acuity in glaucoma.<br><br>Functional assessment with perimetry therefore correlates more closely with daily visual disability than visual acuity alone.<br><br>OCT macula (A) evaluates central retinal structure rather than functional peripheral field impairment.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"During gonioscopy, a patient demonstrates a narrow angle that opens with indentation. Which mechanism is most likely present?",o:["Permanent synechial closure","Traumatic angle recession","Neovascular glaucoma","Appositional angle closure","Congenital trabeculodysgenesis"],a:3,e:"Indentation gonioscopy transiently separates the peripheral iris from the trabecular meshwork in appositional closure.<br><br>This distinction is clinically important because appositional closure may respond better to laser iridotomy before permanent synechiae develop.<br><br>Permanent synechial closure (A) does not reopen significantly with indentation.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A patient has glaucomatous visual field loss respecting the horizontal meridian. Which anatomical structure explains this pattern?",o:["Macular pigment","Lateral geniculate body","Optic chiasm","Horizontal retinal raphe","Corneal endothelium"],a:3,e:"Glaucomatous retinal nerve fiber defects respect the horizontal raphe because superior and inferior nerve fibers do not cross this anatomical boundary.<br><br>Understanding retinal nerve fiber anatomy is essential for interpreting characteristic glaucomatous field defects.<br><br>Optic chiasm lesions (C) produce vertical hemifield defects rather than horizontal raphe-respecting defects.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A patient with severe glaucoma demonstrates tunnel vision. Which visual field finding best describes this stage?",o:["Enlarged blind spot only","Generalized depression with central island remaining","Central scotoma only","Bitemporal hemianopia","Homonymous quadrantanopia"],a:1,e:"Advanced glaucoma progressively destroys peripheral visual fields until only a small central island of vision remains.<br><br>This \"tunnel vision\" pattern represents severe optic nerve damage and significant functional disability.<br><br>Bitemporal hemianopia (D) indicates chiasmal pathology rather than advanced glaucoma.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A patient with suspicious optic discs undergoes OCT. Which finding is most suggestive of early glaucoma?",o:["Diffuse retinal edema","Choroidal thickening","Macular hole","Focal retinal nerve fiber layer thinning","Retinal detachment"],a:3,e:"Localized retinal nerve fiber layer thinning is among the earliest structural changes detectable in glaucoma.<br><br>OCT allows quantitative evaluation of nerve fiber integrity before advanced visual field loss develops.<br><br>Macular hole (C) and retinal detachment (E) represent unrelated vitreoretinal disorders.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A patient with glaucoma has intraocular pressure of 14 mmHg but progressive field defects. Which diagnosis should be strongly considered?",o:["Ocular hypertension","Secondary cataract","Acute angle closure","Normal tension glaucoma","Central retinal vein occlusion"],a:3,e:"Normal tension glaucoma produces characteristic optic nerve and visual field damage despite intraocular pressures within statistically normal ranges.<br><br>Diagnosis depends on correlation of structural and functional glaucomatous changes rather than intraocular pressure alone.<br><br>Ocular hypertension (A) involves elevated IOP without glaucomatous damage. Acute angle closure (C) typically causes markedly elevated IOP.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A patient with glaucoma demonstrates violation of the ISNT rule. Which rim configuration is abnormal?",o:["Inferior \\> Superior \\> Nasal \\> Temporal","Inferior \\> Nasal \\> Superior \\> Temporal","Temporal \\> Inferior \\> Superior \\> Nasal","Inferior \\> Superior \\> Temporal","Nasal \\> Temporal only"],a:2,e:"The ISNT rule states that normal neuroretinal rim thickness decreases Inferior \\> Superior \\> Nasal \\> Temporal. Violation suggests glaucomatous damage.<br><br>Abnormal thinning of the inferior or superior neuroretinal rim is particularly suggestive of glaucoma.<br><br>Option A follows the expected normal rim configuration and therefore does not violate the ISNT rule.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A patient with chronic glaucoma develops a new paracentral scotoma threatening fixation. Which investigation is most important for follow-up?",o:["Serial visual field analysis","Keratometry","Retinoscopy","Amsler grid only","Exophthalmometry"],a:0,e:"Paracentral scotomas threatening fixation require careful serial monitoring because progression may significantly affect reading and daily activities.<br><br>Automated perimetry remains essential for detecting progression and guiding therapeutic escalation.<br><br>Keratometry (B) evaluates corneal curvature and is unrelated to glaucomatous field progression.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A glaucoma patient demonstrates severe optic disc pallor greater than cupping. Which possibility should be considered?",o:["Typical glaucoma only","Nonglaucomatous optic neuropathy","Physiological cupping","Corneal edema","Cataract progression only"],a:1,e:"In glaucoma, cupping usually exceeds pallor. Marked pallor disproportionate to cupping suggests alternative optic nerve pathology such as compressive or ischemic optic neuropathy.<br><br>Recognition of atypical optic disc findings is essential to avoid misdiagnosis of nonglaucomatous optic neuropathies.<br><br>Physiological cupping (C) does not produce progressive pallor or field defects.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A patient with glaucoma undergoes pachymetry demonstrating central corneal thickness of 470 microns. Which implication is most accurate?",o:["Measured IOP may underestimate true pressure","Measured IOP is falsely elevated","Cornea is abnormally thick","Glaucoma risk is reduced","Tonometry becomes invalid"],a:0,e:"Thin corneas cause falsely low applanation tonometry readings and are independently associated with increased glaucoma progression risk.<br><br>Pachymetry therefore contributes significantly to accurate risk stratification and interpretation of intraocular pressure.<br><br>Thick corneas (B, C) produce the opposite effect with falsely elevated readings.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A patient with glaucoma has reproducible arcuate scotomas on automated perimetry. Which retinal fibers are primarily affected?",o:["Papillomacular bundle only","Choroidal vessels","Macular cone fibers only","Arcuate retinal nerve fiber bundles","Optic chiasmal fibers"],a:3,e:"Arcuate scotomas correspond anatomically to damage of superior or inferior arcuate retinal nerve fiber bundles.<br><br>Correlation between retinal nerve fiber anatomy and visual field defects is fundamental in glaucoma interpretation.<br><br>Papillomacular bundle damage (A) more commonly produces central scotomas rather than arcuate defects.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A patient with narrow angles is evaluated at slit lamp before gonioscopy. Which technique estimates peripheral chamber depth?",o:["Van Herick technique","Maddox rod test","Schirmer testing","Hess charting","Ishihara testing"],a:0,e:"The Van Herick slit-lamp technique estimates peripheral anterior chamber depth relative to corneal thickness and screens for occludable angles.<br><br>It provides rapid assessment before formal gonioscopy in patients at risk of angle closure.<br><br>Maddox rod testing (B) evaluates ocular alignment rather than chamber angle anatomy.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A glaucoma suspect has normal visual fields but definite retinal nerve fiber layer loss on OCT. Which interpretation is most accurate?",o:["Glaucoma is excluded","Visual fields are unnecessary","OCT findings are always false positive","Structural damage may precede functional loss","Immediate blindness is expected"],a:3,e:"Retinal nerve fiber layer thinning may occur before detectable visual field defects because structural glaucomatous damage often precedes measurable functional loss.<br><br>Modern glaucoma diagnosis therefore integrates both structural and functional investigations.<br><br>Normal visual fields (A) do not exclude early glaucoma when OCT demonstrates characteristic structural damage.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A patient with progressive glaucoma despite apparently controlled IOP requires reassessment of target pressure. Which principle is most accurate?",o:["Target IOP is identical for all patients","Target pressure is fixed permanently","Visual field progression is irrelevant","Optic disc changes do not matter","Progression may require lower target IOP"],a:4,e:"Target intraocular pressure should be individualized and revised downward when structural or functional progression continues despite apparently controlled measurements.<br><br>Glaucoma management requires continuous reassessment of progression risk and adequacy of pressure reduction.<br><br>Target pressure is not fixed permanently (B) and depends upon disease severity, progression rate, and optic nerve status.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 62-year-old patient with glaucoma develops sudden worsening of visual fields despite stable intraocular pressure readings. Which investigation is most important to exclude noncompliance and pressure fluctuation?",o:["Single office tonometry reading","Diurnal variation curve","Keratometry","Refraction","Schirmer testing"],a:1,e:"A diurnal variation curve evaluates intraocular pressure fluctuations throughout the day and may reveal pressure spikes missed during routine clinic visits.<br><br>Glaucoma progression can occur despite apparently controlled office readings because significant IOP variation may remain undetected without serial measurements.<br><br>Single office tonometry (A) may fail to detect transient spikes. Keratometry (C) evaluates corneal curvature rather than pressure fluctuation.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A glaucoma patient demonstrates progressive thinning of the inferior retinal nerve fiber layer on OCT. Which visual field defect is most likely to develop?",o:["Superior arcuate scotoma","Inferior arcuate scotoma","Bitemporal hemianopia","Central hemianopia","Enlarged blind spot only"],a:0,e:"Damage to the inferior retinal nerve fiber layer produces corresponding superior visual field defects because retinal projections are inverted.<br><br>Correlation between OCT structural abnormalities and visual field defects is fundamental in glaucoma interpretation and progression monitoring.<br><br>Inferior arcuate defects (B) result from superior retinal nerve fiber damage. Bitemporal hemianopia (C) suggests chiasmal disease.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A patient suspected of angle-closure glaucoma undergoes gonioscopy. Which structure is usually identified first in a very narrow angle?",o:["Ciliary body band","Scleral spur","Schwalbe line","Trabecular meshwork posteriorly","Iris root only"],a:2,e:"In extremely narrow angles, Schwalbe line may be the only visible angle structure because more posterior structures become obscured by the peripheral iris.<br><br>Recognition of angle anatomy is essential during gonioscopy for classification and management of glaucoma. Identifying an occludable angle on gonioscopy before dilation is a critical safety checkpoint.<br><br>Visible scleral spur (B) and ciliary body band (A) generally indicate wider angles.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"A patient with glaucoma has optic disc hemorrhage with stable visual fields. Which interpretation is most appropriate?",o:["Disease progression risk remains increased","Hemorrhage excludes glaucoma","Disc hemorrhage is physiologic","Immediate retinal detachment is likely","OCT becomes unnecessary"],a:0,e:"Optic disc hemorrhages are considered markers of active glaucomatous damage and increased progression risk even if visual fields appear temporarily stable.<br><br>Careful structural and functional follow-up is therefore necessary after detection of disc hemorrhages.<br><br>Disc hemorrhage (B) does not exclude glaucoma and is actually strongly associated with glaucomatous optic neuropathy.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A patient undergoing visual field testing demonstrates a cloverleaf pattern. What does this most strongly suggest?",o:["End-stage glaucoma","Papilledema","Bitemporal hemianopia","Macular degeneration","Poor patient reliability"],a:4,e:"A cloverleaf visual field pattern usually indicates poor attention or unreliable patient performance during automated perimetry.<br><br>Interpretation of glaucoma progression requires assessment of test reliability indices before accepting field defects as genuine.<br><br>End-stage glaucoma (A) typically produces severe generalized field constriction rather than cloverleaf artifacts.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"A patient with advanced glaucoma has severe cupping but preserved central acuity. Which retinal fibers are relatively preserved until late disease?",o:["Peripheral arcuate fibers","Choroidal fibers","Nasal retinal fibers only","Inferior retinal fibers only","Papillomacular bundle"],a:4,e:"The papillomacular bundle is often preserved until late glaucoma, allowing central visual acuity to remain relatively intact despite advanced peripheral field loss.<br><br>This explains why patients with severe glaucoma may still read well despite marked functional disability from peripheral vision loss.<br><br>Peripheral arcuate fibers (A) are typically damaged earlier in glaucomatous optic neuropathy.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A patient with suspected glaucoma undergoes pachymetry. Which corneal thickness finding independently increases glaucoma progression risk?",o:["Very thick cornea","Flat cornea","Irregular astigmatism only","Corneal edema only","Thin central cornea"],a:4,e:"Thin central corneal thickness is an independent risk factor for glaucoma progression and may also cause underestimation of true intraocular pressure.<br><br>Corneal thickness therefore contributes significantly to glaucoma risk assessment and therapeutic planning.<br><br>Very thick corneas (A) generally produce falsely elevated pressure readings rather than increased progression risk.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"During glaucoma evaluation, a patient demonstrates progressive vertical enlargement of the optic cup. Which anatomical feature explains this pattern?",o:["Horizontal corneal fibers","Preferential superior and inferior nerve fiber loss","Lens thickening","Macular edema","Choroidal ischemia"],a:1,e:"Glaucoma preferentially damages superior and inferior retinal nerve fibers, producing characteristic vertical enlargement of the optic cup.<br><br>Recognition of vertical cupping is important because it strongly suggests glaucomatous rather than physiological cupping.<br><br>Lens thickening (C) and macular edema (D) do not explain glaucomatous cup enlargement.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A patient with glaucoma progression despite low intraocular pressure undergoes repeat assessment. Which factor should be reviewed carefully before labeling disease as refractory?",o:["Visual field reliability","Hair color","Corneal scar location only","Blood group","Dominant hand"],a:0,e:"Apparent progression on automated perimetry should always be correlated with reliability indices because unreliable fields may falsely suggest deterioration.<br><br>Careful interpretation of fixation losses, false positives, and false negatives is essential in glaucoma follow-up.<br><br>Hair color (B) and blood group (D) have no role in glaucoma progression assessment.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A patient with glaucoma demonstrates diffuse retinal nerve fiber layer loss on OCT but minimal cupping clinically. Which conclusion is most appropriate?",o:["OCT findings are irrelevant","Gonioscopy becomes unnecessary","Glaucoma is excluded","Immediate blindness is inevitable","Structural damage may precede obvious disc excavation"],a:4,e:"Retinal nerve fiber layer loss may become detectable on OCT before marked optic disc excavation develops clinically.<br><br>Modern glaucoma assessment integrates structural imaging with optic disc examination and functional visual field testing for earlier diagnosis.<br><br>Minimal cupping does not exclude glaucoma when OCT demonstrates characteristic nerve fiber layer thinning.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 68-year-old hypermetropic woman develops sudden ocular pain, halos around lights, vomiting, and mid-dilated fixed pupil. Which mechanism most likely precipitated her glaucoma attack?",o:["Trabecular dysgenesis","Optic neuritis","Retinal ischemia","Vitreous hemorrhage","Pupillary block"],a:4,e:"Acute primary angle-closure glaucoma most commonly results from pupillary block causing forward bowing of the peripheral iris and obstruction of the trabecular meshwork.<br><br>Hypermetropia and shallow anterior chamber anatomy significantly increase susceptibility to pupillary block and acute angle closure.<br><br>Trabecular dysgenesis (A) is characteristic of congenital glaucoma rather than acute primary angle closure.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which visual field defect is classically considered the earliest glaucomatous change?",o:["Central scotoma","Bitemporal hemianopia","Altitudinal defect","Homonymous hemianopia","Nasal step"],a:4,e:"The nasal step is an early glaucomatous visual field defect caused by selective damage to retinal nerve fiber bundles respecting the horizontal raphe.<br><br>Recognition of early field loss is important because glaucomatous damage is irreversible once established.<br><br>Bitemporal hemianopia (B) indicates optic chiasmal disease rather than glaucoma. Central scotoma (A) is more typical of optic neuritis.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which surgical procedure is preferred in congenital glaucoma when corneal clarity is adequate?",o:["Trabeculectomy","Goniotomy","Peripheral iridotomy","Cyclocryotherapy","DCR"],a:1,e:"Goniotomy directly incises abnormal trabecular tissue under gonioscopic visualization and is preferred when the cornea is sufficiently clear.<br><br>The procedure improves aqueous outflow and remains a standard surgical treatment for primary congenital glaucoma.<br><br>Peripheral iridotomy (C) is primarily used for angle-closure glaucoma rather than trabeculodysgenesis.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"A glaucoma patient has intraocular pressure within normal range but progressive optic nerve cupping and arcuate scotomas. Which diagnosis is most likely?",o:["Ocular hypertension","Primary angle closure","Normal tension glaucoma","Acute glaucoma","Secondary cataract"],a:2,e:"Normal tension glaucoma produces progressive glaucomatous optic neuropathy despite intraocular pressure measurements within statistically normal limits.<br><br>Diagnosis depends upon characteristic optic disc and visual field changes rather than elevated pressure alone.<br><br>Ocular hypertension (A) involves raised IOP without optic nerve damage. Acute glaucoma (D) typically causes markedly elevated pressure.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which optic disc feature most strongly suggests glaucomatous damage rather than physiological cupping?",o:["Symmetrical small cups","Myelinated nerve fibers","Uniform pale disc","Disc edema","Inferior rim thinning"],a:4,e:"Localized thinning of the superior or inferior neuroretinal rim is highly suggestive of glaucomatous optic neuropathy.<br><br>Glaucoma preferentially damages superior and inferior retinal nerve fiber bundles, leading to characteristic rim loss patterns.<br><br>Disc edema (D) suggests optic nerve swelling rather than glaucomatous cupping.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which corneal finding is classically associated with congenital glaucoma?",o:["Keratic precipitates","Arcus senilis","Corneal guttata","Band keratopathy","Haab striae"],a:4,e:"Haab striae are breaks in Descemet membrane caused by stretching of the cornea due to elevated intraocular pressure in infancy.<br><br>These linear lesions are characteristic ocular findings in congenital glaucoma and may persist into adulthood.<br><br>Keratic precipitates (A) occur in uveitis rather than congenital glaucoma.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which investigation is essential before pupillary dilation in an elderly hypermetropic patient?",o:["OCT macula","Color vision testing","Keratometry","Retinoscopy","Gonioscopy"],a:4,e:"Gonioscopy is essential for evaluating anterior chamber angle anatomy before pharmacologic dilation in patients at risk of angle closure.<br><br>Mydriasis may precipitate acute angle closure in susceptible individuals with narrow angles.<br><br>Keratometry (C) measures corneal curvature and does not evaluate angle anatomy.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which symptom is most characteristic of intermittent angle-closure glaucoma?",o:["Persistent total blindness","Vitreous floaters","Severe ptosis","Continuous diplopia","Intermittent colored halos"],a:4,e:"Intermittent angle closure produces transient episodes of blurred vision and colored halos due to temporary corneal edema from raised intraocular pressure.<br><br>Symptoms often occur in dim illumination when physiological pupillary dilation narrows the angle further.<br><br>Diplopia (D) and floaters (B) are not characteristic manifestations of intermittent angle closure.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which investigation best evaluates functional glaucomatous progression over time?",o:["OCT alone","Automated perimetry","Pachymetry","Schirmer testing","Corneal topography"],a:1,e:"Automated perimetry quantitatively evaluates visual field function and remains fundamental for monitoring glaucomatous progression.<br><br>Serial visual field analysis allows assessment of disease progression and therapeutic response during follow-up.<br><br>Pachymetry (C) measures corneal thickness but does not assess functional visual loss.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which anatomical structure becomes obstructed in primary open-angle glaucoma?",o:["Lens capsule","Optic chiasm","Vitreous cavity","Retinal artery","Trabecular meshwork"],a:4,e:"Primary open-angle glaucoma results from increased resistance to aqueous outflow at the trabecular meshwork despite an anatomically open angle.<br><br>Progressive optic neuropathy develops because of chronically elevated intraocular pressure and retinal ganglion cell loss.<br><br>Retinal artery obstruction (D) causes retinal ischemia rather than glaucoma.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which glaucoma medication is contraindicated during acute angle-closure attack before pressure reduction?",o:["Timolol","Acetazolamide","Pilocarpine initially at very high IOP","Mannitol","Brimonidine"],a:2,e:"Pilocarpine may initially be ineffective in acute angle closure when extremely high intraocular pressure causes ischemia of the iris sphincter muscle.<br><br>Pressure reduction is usually required before miotics become effective in relieving pupillary block. Recognising agents contraindicated during an acute attack is a high-stakes prescribing pitfall.<br><br>Timolol (A) and acetazolamide (B) are standard agents for initial pressure reduction.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which visual field defect is highly characteristic of glaucoma?",o:["Arcuate scotoma","Bitemporal hemianopia","Homonymous hemianopia","Central hemianopia","Monocular temporal defect only"],a:0,e:"Arcuate scotomas follow the course of retinal nerve fiber bundles and represent characteristic glaucomatous field defects.<br><br>These defects typically extend from the blind spot toward the nasal field while respecting the horizontal meridian.<br><br>Bitemporal hemianopia (B) suggests optic chiasmal compression rather than glaucoma.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which finding most strongly differentiates congenital glaucoma from congenital nasolacrimal duct obstruction?",o:["Epiphora","Mild discharge","Enlarged cornea","Lid crusting","Watering while crying"],a:2,e:"Corneal enlargement with elevated intraocular pressure strongly favors congenital glaucoma because infantile ocular tissues stretch under pressure.<br><br>Nasolacrimal duct obstruction may produce tearing but does not enlarge the globe or cornea.<br><br>Epiphora (A) occurs in both conditions and is therefore less specific diagnostically.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which optic disc hemorrhage is strongly associated with active glaucoma progression?",o:["Splinter hemorrhage at disc margin","Preretinal hemorrhage","Subhyaloid hemorrhage","Vitreous hemorrhage","Roth spot"],a:0,e:"Disc margin splinter hemorrhages are strongly associated with ongoing retinal nerve fiber layer damage and glaucomatous progression.<br><br>Detection of optic disc hemorrhage warrants careful reassessment of disease stability and intraocular pressure control.<br><br>Roth spots (E) are associated with hematologic disorders rather than glaucoma progression.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which feature is most typical of acute angle-closure glaucoma on examination?",o:["Constricted reactive pupil","Mid-dilated fixed pupil","Large corneal ulcer","Normal intraocular pressure","Clear cornea"],a:1,e:"Acute angle closure classically produces a mid-dilated sluggish or fixed pupil because iris ischemia impairs sphincter function.<br><br>Corneal edema and markedly elevated intraocular pressure are additional characteristic findings. The characteristic examination signs of an acute attack are an instantly recognisable pattern.<br><br>A clear cornea (E) is unlikely because acute pressure elevation usually produces corneal edema.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which glaucoma investigation directly visualizes the anterior chamber angle?",o:["Pachymetry","Refraction","OCT macula","Automated perimetry","Gonioscopy"],a:4,e:"Gonioscopy directly visualizes anterior chamber angle structures and is indispensable for glaucoma classification.<br><br>It differentiates open-angle glaucoma from angle-closure glaucoma and identifies synechial or appositional closure.<br><br>Perimetry (D) evaluates visual function rather than angle anatomy.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which feature is most characteristic of primary open-angle glaucoma?",o:["Sudden painful visual loss","Acute vomiting episodes","Mid-dilated fixed pupil","Corneal edema attacks","Open anterior chamber angle"],a:4,e:"Primary open-angle glaucoma occurs despite a structurally open anterior chamber angle because aqueous outflow resistance develops within the trabecular meshwork.<br><br>The disease is usually chronic, progressive, and initially asymptomatic.<br><br>Sudden painful attacks (A) are more typical of acute angle-closure glaucoma.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which corneal thickness finding may falsely elevate Goldmann applanation tonometry readings?",o:["Thin cornea","Thick cornea","Corneal ulcer","Corneal edema only","Keratoconus"],a:1,e:"Thick central corneal thickness may falsely elevate applanation tonometry measurements and overestimate true intraocular pressure.<br><br>Interpretation of IOP measurements should therefore incorporate pachymetry findings.<br><br>Thin corneas (A) typically produce falsely low intraocular pressure readings.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which optic nerve feature violates the ISNT rule and suggests glaucoma?",o:["Inferior rim thicker than superior rim","Superior rim thicker than temporal rim","Inferior rim thicker than nasal rim","Nasal rim thicker than temporal rim","Temporal rim thicker than inferior rim"],a:4,e:"The normal ISNT rule states that neuroretinal rim thickness decreases Inferior \\> Superior \\> Nasal \\> Temporal. Violation suggests glaucomatous damage.<br><br>Glaucoma commonly causes preferential thinning of inferior and superior neuroretinal rim tissue.<br><br>Options A, B, D, and E are compatible with the normal ISNT configuration.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A patient with advanced glaucoma still retains good reading vision despite severe peripheral field loss. Which retinal fibers are relatively preserved until late disease?",o:["Arcuate fibers","Peripheral retinal fibers","Papillomacular bundle","Inferior retinal fibers","Choroidal fibers"],a:2,e:"The papillomacular bundle is often preserved until late stages of glaucoma, allowing maintenance of central visual acuity despite severe peripheral visual field constriction.<br><br>This explains why patients may retain reading ability while experiencing profound peripheral visual disability.<br><br>Peripheral arcuate fibers (A) are typically affected earlier during glaucomatous optic neuropathy.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 55-year-old diabetic patient presents with neovascularization of the iris and elevated intraocular pressure. Which type of glaucoma is most likely?",o:["Primary congenital glaucoma","Neovascular glaucoma","Pigmentary glaucoma","Normal tension glaucoma","Phacolytic glaucoma"],a:1,e:"Neovascular glaucoma develops when fibrovascular membranes obstruct the trabecular meshwork, commonly secondary to retinal ischemia from diabetic retinopathy or CRVO.<br><br>Rubeosis iridis with elevated intraocular pressure is a classic high-yield finding. Rubeosis preceding neovascular glaucoma in a diabetic is a frequently tested progression.<br><br>Pigmentary glaucoma (C) results from pigment dispersion rather than iris neovascularization. Congenital glaucoma (A) presents in infancy.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which investigation is most important before performing laser peripheral iridotomy in suspected angle-closure glaucoma?",o:["Keratometry","Hess charting","Schirmer testing","Amsler grid","Gonioscopy"],a:4,e:"Gonioscopy confirms narrow or occludable angles and is essential before laser peripheral iridotomy in angle-closure glaucoma.<br><br>Assessment of angle anatomy guides appropriate management and distinguishes angle closure from other glaucoma mechanisms.<br><br>Schirmer testing (C) evaluates tear production rather than anterior chamber angle configuration.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which glaucoma classically presents with Krukenberg spindle and midperipheral iris transillumination defects?",o:["Neovascular glaucoma","Angle-recession glaucoma","Congenital glaucoma","Phacomorphic glaucoma","Pigmentary glaucoma"],a:4,e:"Pigmentary glaucoma results from liberation of iris pigment, leading to trabecular obstruction, Krukenberg spindle formation, and iris transillumination defects.<br><br>This syndrome is a.<br><br>Angle-recession glaucoma (B) follows blunt trauma rather than pigment dispersion syndrome.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A patient develops glaucoma after blunt ocular trauma. Gonioscopy reveals widened ciliary body band. Which diagnosis is most likely?",o:["Pigmentary glaucoma","Neovascular glaucoma","Angle-recession glaucoma","Phacolytic glaucoma","Congenital glaucoma"],a:2,e:"Angle recession results from splitting of the ciliary body face after blunt trauma and predisposes to secondary open-angle glaucoma.<br><br>Widened ciliary body band on gonioscopy is a classic examination finding emphasized in trauma-related glaucoma recalls.<br><br>Phacolytic glaucoma (D) occurs secondary to leakage of lens proteins from hypermature cataract.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which symptom most strongly suggests acute angle-closure glaucoma rather than open-angle glaucoma?",o:["Gradual peripheral field loss","Severe ocular pain with vomiting","Asymptomatic optic cupping","Slowly progressive nasal step","Chronic elevated IOP only"],a:1,e:"Acute angle closure produces sudden marked elevation of intraocular pressure associated with severe ocular pain, nausea, vomiting, and corneal edema.<br><br>Primary open-angle glaucoma is typically painless and asymptomatic until advanced stages. The symptom cluster pointing to angle closure over other red-eye causes is a recurring discriminator.<br><br>Gradual field loss (A) and asymptomatic cupping (C) are more characteristic of chronic open-angle glaucoma.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which glaucoma medication decreases aqueous humor production by inhibiting carbonic anhydrase?",o:["Pilocarpine","Timolol","Atropine","Latanoprost","Acetazolamide"],a:4,e:"Acetazolamide inhibits carbonic anhydrase in the ciliary body, reducing aqueous humor production and lowering intraocular pressure.<br><br>It is commonly used in acute glaucoma management because of rapid systemic action.<br><br>Pilocarpine (A) increases trabecular outflow through miosis rather than inhibiting aqueous production.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which visual field defect is most characteristic of advanced glaucoma?",o:["Bitemporal hemianopia","Central island of vision only","Homonymous hemianopia","Enlarged blind spot alone","Temporal crescent only"],a:1,e:"Advanced glaucoma progressively destroys peripheral visual fields until only a small central island of vision remains.<br><br>This severe constriction is commonly described as tunnel vision and indicates extensive optic nerve damage.<br><br>Bitemporal hemianopia (A) indicates chiasmal pathology rather than glaucoma.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which sign is most characteristic of congenital glaucoma?",o:["Mid-dilated pupil","Hypopyon","Iris bombe","Posterior synechiae","Haab striae"],a:4,e:"Haab striae are breaks in Descemet membrane caused by stretching of the infantile cornea under elevated intraocular pressure.<br><br>They are classic ocular signs of congenital glaucoma and may persist into adult life.<br><br>Posterior synechiae (D) are associated with uveitis rather than congenital glaucoma.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which glaucoma is classically associated with pseudoexfoliative material on the anterior lens capsule?",o:["Congenital glaucoma","Angle-recession glaucoma","Pigmentary glaucoma","Neovascular glaucoma","Pseudoexfoliative glaucoma"],a:4,e:"Pseudoexfoliative glaucoma results from deposition of fibrillary pseudoexfoliative material within the anterior segment and trabecular meshwork.<br><br>Pigmentary glaucoma (C) involves pigment dispersion rather than fibrillary material deposition.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which optic disc finding most strongly indicates glaucomatous progression?",o:["Disc edema","Choroidal folds","Optic nerve drusen","Pale swollen disc","Progressive vertical cupping"],a:4,e:"Glaucoma preferentially damages superior and inferior retinal nerve fibers, producing characteristic vertical enlargement of the optic cup.<br><br>Serial optic disc assessment is fundamental for identifying progressive glaucomatous optic neuropathy.<br><br>Disc edema (A) suggests raised intracranial pressure or optic neuritis rather than glaucoma.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which glaucoma type is most commonly associated with hypermetropia and shallow anterior chamber?",o:["Primary open-angle glaucoma","Pigmentary glaucoma","Primary angle-closure glaucoma","Neovascular glaucoma","Juvenile glaucoma"],a:2,e:"Hypermetropic eyes tend to have shorter axial length and shallower anterior chambers, predisposing to angle closure.<br><br>Recognition of anatomical risk factors is important for identifying patients susceptible to acute angle-closure attacks.<br><br>Pigmentary glaucoma (B) is more commonly associated with myopia rather than hypermetropia.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which investigation best evaluates retinal nerve fiber layer thickness in glaucoma?",o:["Gonioscopy","OCT","Keratometry","Schiotz tonometry","Amsler grid"],a:1,e:"Optical coherence tomography quantitatively measures retinal nerve fiber layer thickness and optic nerve head structure in glaucoma.<br><br>Structural changes may become detectable before obvious functional visual field loss develops.<br><br>Gonioscopy (A) evaluates angle anatomy rather than retinal nerve fiber integrity.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A patient with hypermature cataract develops painful red eye and elevated intraocular pressure. Which glaucoma is most likely?",o:["Pigmentary glaucoma","Juvenile glaucoma","Congenital glaucoma","Neovascular glaucoma","Phacolytic glaucoma"],a:4,e:"Phacolytic glaucoma occurs when leaked lens proteins from a hypermature cataract obstruct the trabecular meshwork.<br><br>The condition produces secondary open-angle glaucoma with pain, inflammation, and elevated intraocular pressure.<br><br>Neovascular glaucoma (D) is associated with iris neovascularization rather than hypermature cataract.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which investigation directly visualizes the anterior chamber angle structures?",o:["OCT macula","Visual acuity testing","Pachymetry","Refraction","Gonioscopy"],a:4,e:"Gonioscopy directly visualizes angle structures including Schwalbe line, trabecular meshwork, scleral spur, and ciliary body band.<br><br>It remains indispensable in glaucoma classification and management planning.<br><br>Pachymetry (C) measures corneal thickness rather than angle anatomy.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which glaucoma medication increases uveoscleral aqueous outflow?",o:["Timolol","Acetazolamide","Pilocarpine","Latanoprost","Mannitol"],a:3,e:"Latanoprost, a prostaglandin analogue, lowers intraocular pressure primarily by increasing uveoscleral aqueous outflow.<br><br>Prostaglandin analogues are among the most effective first-line therapies for primary open-angle glaucoma.<br><br>Timolol (A) decreases aqueous production rather than increasing outflow.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which symptom pattern is most typical of primary open-angle glaucoma?",o:["Sudden painful visual loss","Gradual painless peripheral field loss","Severe photophobia and tearing","Acute vomiting attacks","Sudden complete blindness"],a:1,e:"Primary open-angle glaucoma progresses slowly and painlessly, often causing unnoticed peripheral visual field loss until advanced stages.<br><br>Because early disease is usually asymptomatic, regular screening is important in high-risk individuals.<br><br>Sudden painful attacks (A) are characteristic of acute angle-closure glaucoma rather than POAG.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which feature most strongly favors physiological optic cupping rather than glaucoma?",o:["Progressive visual field loss","Disc hemorrhage","Nasal step defect","Inferior rim thinning","Symmetric large cups with healthy rims"],a:4,e:"Physiological cupping may produce large but symmetrical optic cups with preserved neuroretinal rim integrity and normal visual fields.<br><br>Assessment of rim health and progression is critical for differentiating physiological cupping from glaucomatous optic neuropathy.<br><br>Disc hemorrhages (B) and nasal step defects (C) strongly suggest glaucoma rather than physiological cupping.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which finding most strongly indicates unreliable automated perimetry?",o:["Arcuate scotoma","Nasal step","High fixation losses","Paracentral defect","Seidel scotoma"],a:2,e:"High fixation losses indicate poor reliability during automated visual field testing and may invalidate interpretation of glaucomatous progression.<br><br>Reliable patient fixation and response consistency are essential for accurate perimetric assessment.<br><br>Arcuate scotomas (A) and nasal steps (B) are characteristic glaucomatous defects rather than reliability indices.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which anatomical structure is damaged in glaucomatous optic neuropathy?",o:["Photoreceptors only","Choroidal melanocytes","Corneal epithelium","Lens nucleus","Retinal ganglion cell axons"],a:4,e:"Glaucoma primarily damages retinal ganglion cell axons, leading to optic nerve cupping and progressive visual field loss.<br><br>Loss of retinal nerve fibers produces characteristic structural and functional glaucomatous changes.<br><br>Photoreceptors (A) are primarily affected in retinal dystrophies rather than glaucoma.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which statement regarding glaucoma is most accurate?",o:["Normal intraocular pressure excludes glaucoma","Glaucoma always causes symptoms early","Visual acuity loss occurs first in all glaucoma patients","Gonioscopy has no role in glaucoma assessment","Structural optic nerve damage may precede visual field loss"],a:4,e:"Structural glaucomatous changes, including retinal nerve fiber layer thinning and optic disc cupping, may develop before detectable visual field defects appear.<br><br>Modern glaucoma diagnosis therefore combines structural imaging with functional perimetric assessment.<br><br>Normal intraocular pressure (A) does not exclude normal tension glaucoma. Gonioscopy (D) remains essential in glaucoma classification.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 64-year-old woman presents with severe ocular pain, headache, vomiting, and colored halos around lights. Examination shows corneal edema and a fixed mid-dilated pupil. Which immediate definitive procedure is most appropriate after initial medical control?",o:["Trabeculectomy","Penetrating keratoplasty","Vitrectomy","DCR","Laser peripheral iridotomy"],a:4,e:"Laser peripheral iridotomy creates an alternative aqueous pathway between posterior and anterior chambers, relieving pupillary block in angle-closure glaucoma.<br><br>It is considered the definitive treatment for primary pupillary block angle closure after acute intraocular pressure reduction.<br><br>Trabeculectomy (A) may be required later in refractory disease but is not first-line definitive treatment for acute pupillary block.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which optic disc finding is considered highly suspicious for glaucomatous optic neuropathy in FCPS recalls?",o:["Cup-disc ratio asymmetry \\>0.2","Macular star","Optic disc edema","Cherry-red spot","Myelinated fibers"],a:0,e:"Significant asymmetry in cup-disc ratio between eyes strongly suggests glaucomatous optic nerve damage, especially when associated with rim thinning.<br><br>Asymmetric cupping is.<br><br>Macular star (B) suggests neuroretinitis rather than glaucoma. Optic disc edema (C) indicates swelling, not glaucomatous cupping.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which anti-glaucoma drug is contraindicated in bronchial asthma?",o:["Acetazolamide","Pilocarpine","Timolol","Mannitol","Latanoprost"],a:2,e:"Timolol is a nonselective beta-blocker and may precipitate bronchospasm in patients with asthma or chronic obstructive pulmonary disease.<br><br>Systemic side effects of topical beta-blockers are.<br><br>Pilocarpine (B) mainly causes miosis and accommodative spasm rather than bronchospasm.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which visual field defect is classically associated with early glaucoma?",o:["Ring scotoma","Central scotoma","Homonymous quadrantanopia","Bitemporal hemianopia","Nasal step"],a:4,e:"The nasal step results from selective retinal nerve fiber bundle loss respecting the horizontal raphe and is a classic early glaucomatous field defect.<br><br>Early detection of characteristic visual field abnormalities is fundamental in glaucoma diagnosis and follow-up.<br><br>Bitemporal hemianopia (D) indicates chiasmal compression rather than glaucoma.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A patient with glaucoma develops optic disc hemorrhage during follow-up despite controlled intraocular pressure. What does this most strongly suggest?",o:["Stable disease","Cataract progression","Active glaucomatous progression","Retinal detachment","Physiological cupping"],a:2,e:"Optic disc splinter hemorrhages are strongly associated with ongoing retinal nerve fiber layer damage and progression of glaucoma.<br><br>Disc hemorrhage is considered a poor prognostic sign and warrants reassessment of therapeutic adequacy.<br><br>Physiological cupping (E) does not produce disc hemorrhages or progressive field loss.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which glaucoma is most commonly associated with pseudoexfoliative material deposition?",o:["Primary congenital glaucoma","Pigmentary glaucoma","Juvenile glaucoma","Neovascular glaucoma","Pseudoexfoliative glaucoma"],a:4,e:"Pseudoexfoliative glaucoma occurs due to deposition of fibrillary material on anterior segment structures and trabecular meshwork.<br><br>It commonly produces aggressive secondary open-angle glaucoma with high intraocular pressure fluctuations.<br><br>Pigmentary glaucoma (B) results from pigment dispersion rather than pseudoexfoliative deposits.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which investigation remains the gold standard for intraocular pressure measurement?",o:["Non-contact tonometry","Schiotz tonometry","Goldmann applanation tonometry","Rebound tonometry","Digital palpation"],a:2,e:"Goldmann applanation tonometry remains the reference standard for accurate intraocular pressure assessment in glaucoma practice.<br><br>Precise IOP measurement is essential for diagnosis, therapeutic monitoring, and progression assessment.<br><br>Digital palpation (E) is highly subjective and unsuitable for accurate glaucoma evaluation.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which feature most strongly differentiates acute angle-closure glaucoma from acute conjunctivitis?",o:["Red eye","Watering","Markedly elevated intraocular pressure","Mild photophobia","Conjunctival injection"],a:2,e:"Acute angle closure produces marked elevation of intraocular pressure with corneal edema and fixed mid-dilated pupil.<br><br>Conjunctival injection (E) and watering (B) may occur in both disorders and are less specific. Features differentiating acute glaucoma from a benign red eye are a classic emergency discriminator.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which retinal fibers are preferentially damaged earliest in glaucoma?",o:["Papillomacular fibers only","Choroidal fibers","Macular cone fibers","Nasal retinal fibers only","Superior and inferior arcuate fibers"],a:4,e:"Glaucoma preferentially damages superior and inferior retinal nerve fiber bundles, producing arcuate scotomas and vertical cupping.<br><br>This characteristic anatomical vulnerability explains many classical glaucomatous field defects.<br><br>Papillomacular fibers (A) are relatively preserved until late disease.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which condition is classically associated with neovascular glaucoma?",o:["Retinitis pigmentosa","Proliferative diabetic retinopathy","Keratoconus","Optic neuritis","High myopia"],a:1,e:"Retinal ischemia from proliferative diabetic retinopathy stimulates VEGF-mediated iris neovascularization leading to neovascular glaucoma.<br><br>Keratoconus (C) is a corneal ectatic disorder unrelated to neovascular glaucoma.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which anti-glaucoma medication commonly causes eyelash growth and iris pigmentation?",o:["Timolol","Acetazolamide","Pilocarpine","Latanoprost","Brinzolamide"],a:3,e:"Latanoprost, a prostaglandin analogue, may cause increased eyelash growth, periocular pigmentation, and irreversible iris darkening.<br><br>Timolol (A) more commonly causes systemic beta-blocker adverse effects rather than iris pigmentation.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which gonioscopic finding is most suggestive of angle recession after blunt trauma?",o:["Narrow angle only","Peripheral anterior synechiae","Schwalbe line prominence only","Iris bombe","Widened ciliary body band"],a:4,e:"Angle recession occurs due to splitting of ciliary body musculature following blunt trauma and appears as widened ciliary body band on gonioscopy.<br><br>Traumatic glaucoma is a.<br><br>Peripheral anterior synechiae (B) are more typical of chronic angle closure rather than angle recession.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which glaucoma surgery creates a fistula for aqueous drainage into subconjunctival space?",o:["Goniotomy","Vitrectomy","Iridotomy","Cycloplegia","Trabeculectomy"],a:4,e:"Trabeculectomy lowers intraocular pressure by creating a guarded fistula that allows aqueous drainage into a subconjunctival bleb.<br><br>It remains a standard surgical procedure for medically uncontrolled glaucoma.<br><br>Goniotomy (A) is mainly used in congenital glaucoma.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which feature is most characteristic of chronic primary open-angle glaucoma?",o:["Sudden painful onset","Acute corneal edema","Gradual painless visual field loss","Fixed mid-dilated pupil","Severe nausea and vomiting"],a:2,e:"Primary open-angle glaucoma progresses slowly and painlessly with gradual peripheral field constriction.<br><br>Patients often remain asymptomatic until advanced optic nerve damage has occurred.<br><br>Acute painful symptoms (A, E) are characteristic of angle-closure attacks rather than POAG.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which corneal finding is especially associated with congenital glaucoma?",o:["Corneal guttata","Band keratopathy","Arcus senilis","Dendritic ulcer","Haab striae"],a:4,e:"Haab striae are breaks in Descemet membrane produced by stretching of the infantile cornea due to elevated intraocular pressure.<br><br>Recognition of these lesions is essential in pediatric glaucoma diagnosis.<br><br>Corneal guttata (A) are associated with endothelial dystrophies rather than congenital glaucoma.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which optic disc feature is most suggestive of glaucoma progression?",o:["Increased vertical cup enlargement","Disc edema","Optic pallor without cupping","Cherry-red spot","Macular exudates"],a:0,e:"Progressive vertical enlargement of the optic cup reflects preferential superior and inferior nerve fiber damage in glaucoma.<br><br>Serial optic disc evaluation remains central to glaucoma monitoring.<br><br>Optic pallor greater than cupping (C) suggests nonglaucomatous optic neuropathy.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which factor is an established risk factor for primary open-angle glaucoma?",o:["Hyperopia only","High fever","Retinal detachment","Corneal ulcer","Increasing age"],a:4,e:"Increasing age is among the strongest risk factors for primary open-angle glaucoma because optic nerve susceptibility rises with aging.<br><br>Family history, African ancestry, and elevated intraocular pressure are additional important risk factors.<br><br>Corneal ulceration (D) is unrelated to POAG risk.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which visual field defect is produced by glaucoma due to retinal nerve fiber bundle damage?",o:["Arcuate scotoma","Bitemporal hemianopia","Homonymous hemianopia","Central hemianopia","Junctional scotoma"],a:0,e:"Arcuate scotomas follow the anatomical distribution of retinal nerve fiber bundles damaged in glaucoma.<br><br>These defects characteristically respect the horizontal meridian and are highly tested in glaucoma recalls.<br><br>Homonymous hemianopia (C) indicates retrochiasmal neurological disease rather than glaucoma.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which investigation directly measures central corneal thickness in glaucoma evaluation?",o:["Keratometry","Pachymetry","Gonioscopy","Retinoscopy","OCT macula"],a:1,e:"Pachymetry measures central corneal thickness, which significantly influences interpretation of applanation tonometry readings.<br><br>Thin corneas may underestimate true IOP and are independently associated with increased glaucoma progression risk.<br><br>Keratometry (A) evaluates corneal curvature rather than thickness.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which statement regarding glaucoma is most accurate and repeatedly emphasized in FCPS recalls?",o:["Normal intraocular pressure excludes glaucoma","Visual acuity loss occurs early in all cases","Acute pain is universal in glaucoma","Gonioscopy is unnecessary in glaucoma","Structural optic nerve damage may precede field loss"],a:4,e:"Structural retinal nerve fiber layer thinning and optic disc cupping may develop before detectable visual field defects appear.<br><br>Modern glaucoma assessment therefore integrates structural imaging and functional perimetry for early diagnosis.<br><br>Normal intraocular pressure (A) does not exclude normal tension glaucoma. Acute pain (C) is absent in many glaucoma subtypes.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 70-year-old patient with chronic glaucoma demonstrates progressive visual field loss despite apparently controlled intraocular pressure. Which factor should be reassessed first?",o:["Hair color","Blood group","Central corneal scar size","Target intraocular pressure adequacy","Dominant hand"],a:3,e:"Progression despite apparently controlled pressure suggests that the individualized target intraocular pressure may still be insufficient for that optic nerve.<br><br>Target IOP varies according to disease severity, rate of progression, and optic nerve susceptibility.<br><br>Blood group (B) and dominant hand (E) have no role in glaucoma progression assessment.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which glaucoma medication is most likely to cause irreversible iris pigmentation?",o:["Timolol","Pilocarpine","Acetazolamide","Brimonidine","Latanoprost"],a:4,e:"Latanoprost, a prostaglandin analogue, commonly causes gradual iris darkening due to increased melanin production within stromal melanocytes.<br><br>Timolol (A) mainly causes systemic beta-blocker side effects rather than iris pigmentation.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A patient with acute angle-closure glaucoma presents with corneal edema and fixed mid-dilated pupil. Which mechanism primarily produces the corneal haze?",o:["Retinal ischemia","Endothelial pump dysfunction from elevated IOP","Optic nerve edema","Lens protein leakage","Choroidal effusion"],a:1,e:"Markedly elevated intraocular pressure impairs corneal endothelial pump function, resulting in stromal edema and hazy cornea.<br><br>Corneal edema contributes significantly to blurred vision and colored halos during acute glaucoma attacks. The triad of corneal oedema, mid-dilated pupil and rock-hard globe is a hallmark presentation worth instant recognition.<br><br>Lens protein leakage (D) occurs in phacolytic glaucoma rather than primary acute angle closure.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which optic disc change most strongly suggests progression of glaucomatous optic neuropathy?",o:["Increasing neuroretinal rim thinning","Disc hyperemia only","Macular exudation","Choroidal folds","Papilledema"],a:0,e:"Progressive thinning of the neuroretinal rim reflects ongoing retinal ganglion cell axonal loss in glaucoma.<br><br>Serial optic disc assessment is essential for detecting structural progression before severe functional deterioration occurs.<br><br>Papilledema (E) indicates raised intracranial pressure rather than glaucoma progression.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which condition is most strongly associated with secondary neovascular glaucoma?",o:["Keratoconus","Retinitis pigmentosa","Central retinal vein occlusion","Myopia","Optic neuritis"],a:2,e:"Retinal ischemia from central retinal vein occlusion stimulates VEGF-mediated iris neovascularization leading to neovascular glaucoma.<br><br>Keratoconus (A) is a corneal ectatic disorder unrelated to neovascular glaucoma.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which investigation is most useful for detecting early structural glaucomatous damage before visual field loss?",o:["OCT retinal nerve fiber layer analysis","Schirmer testing","Keratometry","Hess charting","Color vision testing only"],a:0,e:"OCT can quantitatively detect retinal nerve fiber layer thinning before obvious functional defects appear on perimetry.<br><br>Early structural diagnosis permits earlier intervention and may improve long-term visual outcomes.<br><br>Schirmer testing (B) evaluates tear production and has no role in glaucoma diagnosis.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A patient with blunt ocular trauma develops glaucoma years later. Which gonioscopic finding is classically associated with this condition?",o:["Iris bombe","Narrow angle","Peripheral anterior synechiae only","Widened ciliary body band","Dense pseudoexfoliative deposits"],a:3,e:"Angle recession after blunt trauma causes separation within ciliary body musculature and appears as widened ciliary body band on gonioscopy.<br><br>This traumatic glaucoma mechanism is.<br><br>Pseudoexfoliative deposits (E) are unrelated to traumatic glaucoma.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which visual field defect is classically associated with advanced glaucoma?",o:["Enlarged blind spot only","Junctional scotoma","Bitemporal hemianopia","Homonymous hemianopia","Tunnel vision with central island"],a:4,e:"Advanced glaucoma progressively destroys peripheral visual fields until only a small central island remains.<br><br>This severe constriction reflects extensive optic nerve damage and major functional disability.<br><br>Bitemporal hemianopia (C) indicates chiasmal pathology rather than glaucoma.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which risk factor is particularly associated with primary angle-closure glaucoma?",o:["High axial myopia","Deep anterior chamber","Large corneal diameter","Retinal degeneration","Hypermetropia"],a:4,e:"Hypermetropic eyes tend to have shorter axial lengths and shallow anterior chambers, predisposing to angle closure.<br><br>Recognition of anatomical risk factors is important for preventing acute angle-closure attacks.<br><br>High myopia (A) is more commonly associated with pigment dispersion and open-angle mechanisms.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which glaucoma medication commonly produces accommodative spasm and brow ache?",o:["Timolol","Acetazolamide","Latanoprost","Pilocarpine","Brinzolamide"],a:3,e:"Pilocarpine causes ciliary muscle contraction resulting in accommodative spasm, brow ache, and induced myopia.<br><br>These side effects are important clinically and commonly appear in pharmacology-based glaucoma recalls.<br><br>Latanoprost (C) primarily increases uveoscleral outflow and causes iris pigmentation rather than accommodative spasm.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which structure is directly damaged in glaucomatous optic neuropathy?",o:["Corneal epithelium","Photoreceptor outer segments only","Lens fibers","Choroidal melanocytes","Retinal ganglion cell axons"],a:4,e:"Glaucoma primarily damages retinal ganglion cell axons, producing optic disc cupping and characteristic visual field loss.<br><br>Retinal nerve fiber layer loss correlates closely with glaucomatous progression.<br><br>Lens fibers (C) are primarily affected in cataract rather than glaucoma.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A patient develops painful glaucoma associated with hypermature cataract and leaking lens proteins. Which diagnosis is most likely?",o:["Pigmentary glaucoma","Neovascular glaucoma","Juvenile glaucoma","Phacolytic glaucoma","Congenital glaucoma"],a:3,e:"Phacolytic glaucoma occurs when high-molecular-weight lens proteins leak through a hypermature cataract capsule and obstruct aqueous outflow.<br><br>This produces secondary open-angle glaucoma with pain, inflammation, and markedly elevated IOP.<br><br>Pigmentary glaucoma (A) results from iris pigment dispersion rather than lens protein leakage.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which optic disc feature most strongly differentiates physiological cupping from glaucoma?",o:["Symmetric large cups with intact rims","Disc hemorrhage","Inferior rim notching","Progressive cupping","Nasal step defect"],a:0,e:"Physiological cupping may produce large but symmetrical cups with healthy neuroretinal rims and normal visual fields.<br><br>Glaucoma typically causes progressive asymmetry, rim thinning, and characteristic field defects.<br><br>Disc hemorrhage (B) strongly suggests active glaucomatous damage rather than physiological cupping.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which investigation is indispensable for differentiating open-angle from angle-closure glaucoma?",o:["Pachymetry","OCT macula","Automated perimetry","Gonioscopy","Refraction"],a:3,e:"Gonioscopy directly visualizes anterior chamber angle anatomy and remains essential for glaucoma classification.<br><br>Management differs substantially between open-angle and angle-closure mechanisms, making gonioscopy indispensable.<br><br>Perimetry (C) evaluates functional loss but does not classify angle anatomy.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which feature is most characteristic of pigmentary glaucoma?",o:["Rubeosis iridis","Mid-dilated fixed pupil","Krukenberg spindle","Haab striae","Iris bombe"],a:2,e:"Pigment dispersion syndrome produces vertical spindle-shaped pigment deposition on the corneal endothelium known as Krukenberg spindle.<br><br>Haab striae (D) are associated with congenital glaucoma rather than pigment dispersion syndrome.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which visual field defect classically respects the horizontal meridian in glaucoma?",o:["Homonymous hemianopia","Arcuate scotoma","Bitemporal hemianopia","Central hemianopia","Altitudinal neurological defect"],a:1,e:"Arcuate scotomas follow the anatomy of retinal nerve fiber bundles and therefore respect the horizontal raphe.<br><br>This pattern is characteristic of glaucomatous visual field damage.<br><br>Homonymous hemianopia (A) respects the vertical meridian and indicates retrochiasmal lesions.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which condition most strongly predisposes to steroid-induced glaucoma?",o:["Long-term corticosteroid therapy","Hyperthyroidism","Corneal abrasion","Acute conjunctivitis","Vitreous floaters"],a:0,e:"Prolonged corticosteroid use can increase trabecular outflow resistance and produce secondary open-angle glaucoma.<br><br>Corneal abrasion (C) does not independently predispose to steroid glaucoma.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which finding most strongly suggests congenital glaucoma in an infant?",o:["Small corneal diameter","Retinal hemorrhage","Vitreous opacities","Posterior synechiae","Corneal enlargement with photophobia"],a:4,e:"Elevated intraocular pressure in infancy enlarges the elastic cornea and globe, producing buphthalmos and photophobia.<br><br>This presentation is classic for congenital glaucoma and highly emphasized in pediatric ophthalmology recalls.<br><br>Posterior synechiae (D) indicate uveitis rather than congenital glaucoma.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which anti-glaucoma medication acts primarily by increasing trabecular aqueous outflow through miosis?",o:["Timolol","Acetazolamide","Latanoprost","Pilocarpine","Brimonidine"],a:3,e:"Pilocarpine contracts the ciliary muscle and opens trabecular spaces, enhancing aqueous outflow through the conventional pathway.<br><br>Miotic therapy historically played an important role in angle-closure management.<br><br>Timolol (A) lowers IOP by reducing aqueous production rather than increasing trabecular outflow.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which statement regarding glaucoma is most accurate?",o:["Normal IOP completely excludes glaucoma","Visual acuity is affected first in all cases","Glaucoma always presents painfully","Structural optic nerve damage may precede field loss","Gonioscopy is obsolete in modern glaucoma care"],a:3,e:"Retinal nerve fiber layer thinning and optic disc cupping may become detectable before obvious functional visual field defects appear.<br><br>Modern glaucoma diagnosis therefore integrates structural imaging and functional assessment for early detection.<br><br>Normal intraocular pressure (A) does not exclude normal tension glaucoma. Gonioscopy (E) remains essential in glaucoma evaluation.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 65-year-old woman presents with sudden severe ocular pain, headache, nausea, and halos around lights. Examination reveals corneal edema and a fixed mid-dilated pupil. Which diagnosis is most likely?",o:["Acute iridocyclitis","Central retinal artery occlusion","Primary open-angle glaucoma","Acute angle-closure glaucoma","Optic neuritis"],a:3,e:"Acute angle-closure glaucoma classically presents with sudden painful red eye, corneal edema, vomiting, and markedly elevated intraocular pressure.<br><br>Acute iridocyclitis (A) usually presents with constricted pupil rather than fixed mid-dilated pupil. CRAO (B) causes painless visual loss.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which investigation is considered indispensable before diagnosing primary open-angle glaucoma?",o:["Keratometry","Color vision testing","Schirmer testing","Retinoscopy","Gonioscopy"],a:4,e:"Gonioscopy is essential to confirm an open anterior chamber angle before labeling glaucoma as primary open-angle type.<br><br>Correct glaucoma classification is critical because management differs substantially between open-angle and angle-closure mechanisms.<br><br>Retinoscopy (D) assesses refractive error rather than angle anatomy.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which glaucoma medication is contraindicated in patients with bronchial asthma?",o:["Timolol","Latanoprost","Pilocarpine","Brinzolamide","Acetazolamide"],a:0,e:"Timolol is a nonselective beta-blocker that may precipitate life-threatening bronchospasm in asthmatic patients.<br><br>Systemic adverse effects of topical beta-blockers are.<br><br>Latanoprost (B) mainly causes iris pigmentation and eyelash growth rather than bronchospasm.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which visual field defect is classically associated with early glaucomatous damage?",o:["Homonymous hemianopia","Central hemianopia","Nasal step","Bitemporal hemianopia","Junctional scotoma"],a:2,e:"The nasal step develops because glaucomatous retinal nerve fiber damage respects the horizontal raphe.<br><br>Recognition of early field defects is essential because glaucomatous damage is irreversible once established.<br><br>Bitemporal hemianopia (D) suggests optic chiasmal pathology rather than glaucoma.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A patient with proliferative diabetic retinopathy develops painful glaucoma with rubeosis iridis. Which glaucoma is most likely?",o:["Pigmentary glaucoma","Phacolytic glaucoma","Congenital glaucoma","Neovascular glaucoma","Juvenile glaucoma"],a:3,e:"Retinal ischemia stimulates VEGF production causing iris neovascularization and secondary angle obstruction.<br><br>Pigmentary glaucoma (A) is caused by pigment dispersion rather than retinal ischemia.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which optic disc feature most strongly suggests glaucomatous progression?",o:["Disc edema","Optic disc drusen","Choroidal folds","Macular star","Progressive vertical cupping"],a:4,e:"Glaucoma preferentially damages superior and inferior retinal nerve fibers, producing progressive vertical enlargement of the optic cup.<br><br>Serial optic nerve assessment remains central in glaucoma monitoring and progression analysis.<br><br>Disc edema (A) suggests raised intracranial pressure or optic neuritis rather than glaucoma.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which glaucoma surgery creates a guarded fistula beneath the conjunctiva?",o:["Goniotomy","Trabeculotomy","Cyclodialysis","Iridotomy","Trabeculectomy"],a:4,e:"Trabeculectomy lowers intraocular pressure by diverting aqueous humor into a subconjunctival filtering bleb.<br><br>It remains the standard filtration surgery for medically uncontrolled glaucoma.<br><br>Goniotomy (A) is mainly used for congenital glaucoma rather than adult filtration surgery.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which finding is most characteristic of congenital glaucoma?",o:["Mid-dilated pupil","Hypopyon","Iris bombe","Posterior synechiae","Haab striae"],a:4,e:"Haab striae are breaks in Descemet membrane caused by stretching of the infantile cornea under elevated intraocular pressure.<br><br>Posterior synechiae (D) are associated with anterior uveitis rather than congenital glaucoma.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which anti-glaucoma drug increases uveoscleral outflow?",o:["Timolol","Acetazolamide","Pilocarpine","Mannitol","Latanoprost"],a:4,e:"Latanoprost lowers intraocular pressure primarily by enhancing uveoscleral aqueous outflow.<br><br>Prostaglandin analogues are highly effective first-line agents in primary open-angle glaucoma.<br><br>Timolol (A) reduces aqueous production rather than increasing outflow.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which condition most strongly predisposes to primary angle-closure glaucoma?",o:["High myopia","Deep anterior chamber","Hypermetropia","Large corneal diameter","Keratoconus"],a:2,e:"Hypermetropic eyes are shorter with shallow anterior chambers, predisposing to pupillary block and angle closure.<br><br>High myopia (A) is more commonly associated with open-angle mechanisms.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which investigation directly evaluates retinal nerve fiber layer thickness?",o:["Gonioscopy","Automated perimetry","Pachymetry","OCT","Keratometry"],a:3,e:"Optical coherence tomography quantitatively assesses retinal nerve fiber layer thickness and optic nerve head structure.<br><br>Structural damage may become evident on OCT before detectable field defects appear.<br><br>Perimetry (B) evaluates functional visual field loss rather than structural nerve fiber integrity.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A patient develops glaucoma years after blunt ocular trauma. Which gonioscopic finding is expected?",o:["Narrow angle","Iris bombe","Rubeosis iridis","Posterior synechiae","Widened ciliary body band"],a:4,e:"Angle recession occurs due to splitting within the ciliary body face after blunt trauma.<br><br>Widened ciliary body band on gonioscopy is the classic hallmark of angle-recession glaucoma.<br><br>Rubeosis iridis (C) is characteristic of neovascular glaucoma rather than traumatic angle recession.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which symptom pattern is most characteristic of primary open-angle glaucoma?",o:["Sudden painful blindness","Gradual painless peripheral field loss","Severe photophobia with tearing","Acute vomiting attacks","Colored halos with red eye"],a:1,e:"Primary open-angle glaucoma progresses slowly and silently with gradual peripheral visual field constriction.<br><br>Many patients remain asymptomatic until advanced optic nerve damage has occurred.<br><br>Colored halos with painful red eye (E) suggest acute angle closure rather than POAG.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which anti-glaucoma drug commonly causes brow ache and accommodative spasm?",o:["Timolol","Brimonidine","Acetazolamide","Pilocarpine","Latanoprost"],a:3,e:"Pilocarpine stimulates ciliary muscle contraction causing accommodative spasm, brow ache, and induced myopia.<br><br>These side effects are frequently tested in glaucoma pharmacology MCQs.<br><br>Timolol (A) more commonly causes systemic beta-blocker adverse effects.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which feature most strongly differentiates physiological cupping from glaucoma?",o:["Progressive visual field defects","Nasal step defect","Inferior rim thinning","Disc hemorrhage","Symmetric large cups with healthy rims"],a:4,e:"Physiological cupping may produce large symmetric cups without neuroretinal rim loss or field defects.<br><br>Glaucoma typically demonstrates progression, asymmetry, rim thinning, and characteristic perimetric abnormalities.<br><br>Disc hemorrhage (D) strongly suggests active glaucomatous damage rather than physiological cupping.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which glaucoma is classically associated with Krukenberg spindle?",o:["Neovascular glaucoma","Congenital glaucoma","Pigmentary glaucoma","Phacomorphic glaucoma","Juvenile glaucoma"],a:2,e:"Pigment dispersion syndrome causes liberation of iris pigment with deposition on the corneal endothelium as Krukenberg spindle.<br><br>This classic slit-lamp finding is.<br><br>Phacomorphic glaucoma (D) results from swollen cataractous lens causing angle closure.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which investigation measures central corneal thickness in glaucoma workup?",o:["Pachymetry","Gonioscopy","Retinoscopy","OCT macula","Automated perimetry"],a:0,e:"Pachymetry measures central corneal thickness, which significantly affects Goldmann applanation tonometry interpretation.<br><br>Thin corneas may underestimate true IOP and increase glaucoma progression risk.<br><br>Perimetry (E) evaluates functional field loss rather than corneal thickness.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which visual field defect is most characteristic of advanced glaucoma?",o:["Enlarged blind spot only","Junctional scotoma","Homonymous hemianopia","Bitemporal hemianopia","Central island with tunnel vision"],a:4,e:"Advanced glaucoma causes severe peripheral visual field constriction leaving only a residual central island.<br><br>This pattern reflects extensive retinal ganglion cell and optic nerve damage.<br><br>Homonymous hemianopia (C) indicates retrochiasmal neurological disease rather than glaucoma.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which statement regarding normal tension glaucoma is most accurate?",o:["Elevated IOP is mandatory for diagnosis","Optic nerve damage may occur despite normal IOP","Gonioscopy is always abnormal","Visual fields remain permanently normal","Disc cupping never develops"],a:1,e:"Normal tension glaucoma produces characteristic glaucomatous optic neuropathy despite statistically normal intraocular pressure measurements.<br><br>Diagnosis relies on optic disc and visual field findings rather than elevated pressure alone.<br><br>Disc cupping (E) commonly develops in normal tension glaucoma.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which statement regarding glaucoma diagnosis is most accurate and highly emphasized in FCPS recalls?",o:["Normal IOP excludes glaucoma completely","Gonioscopy is unnecessary in modern practice","Structural optic nerve damage may precede field loss","Glaucoma always presents painfully","Visual acuity loss occurs first in all patients"],a:2,e:"Retinal nerve fiber layer thinning and optic disc cupping may develop before detectable visual field defects become apparent.<br><br>Modern glaucoma diagnosis therefore combines structural imaging with functional perimetry for earlier disease detection.<br><br>Normal IOP (A) does not exclude normal tension glaucoma. Painful presentation (D) occurs mainly in acute angle closure.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
];